export default function AnalyticsPage() {
  const [rangeDays, setRangeDays] = useState(30)
  const [clients, setClients] = useState<Client[]>([])
  const [visitData, setVisitData] = useState<any[]>([])
  const [commissionData, setCommissionData] = useState<any[]>([])
  const [funnel, setFunnel] = useState<any>(null)
  const [placementsByStatus, setPlacementsByStatus] = useState<any[]>([])
  const [placementsByBrand, setPlacementsByBrand] = useState<Record<string, number>>({})
  const [visitsByStatus, setVisitsByStatus] = useState<{ status: string; count: number }[]>([])
  const [visitsByStatusGrouped, setVisitsByStatusGrouped] = useState<Record<string, any[]>>({})
  const [expandedStatus, setExpandedStatus] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)
  const [profile, setProfile] = useState<any>(null)
  const [visitModal, setVisitModal] = useState<{ open: boolean; accountId?: string; accountName?: string }>({ open: false })
  const [dismissedIds, setDismissedIds] = useState<Set<string>>(new Set())
  const [showAllByStatus, setShowAllByStatus] = useState<Record<string, boolean>>({})
  const [visitCounts, setVisitCounts] = useState<{ total: number; unique: number } | null>(null)
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  useEffect(() => {
    const sb = getSupabase()
    sb.auth.getUser().then(async ({ data: { user } }) => {
      if (user) {
        const { data: p } = await sb.from('user_profiles').select('*').eq('id', user.id).single()
        if (p) setProfile(p)
      }
    })
  }, [])

  useEffect(() => {
    setDismissedIds(new Set())
    setShowAllByStatus({})
    setVisitCounts(null)
    setLoading(true)
    setExpandedStatus(null)
    const end = new Date()
    const start = new Date(nDaysAgoMT(rangeDays))

    Promise.all([
      getClients(),
      getVisitTrend({ start, end }),
      getPlacementFunnel({ start, end }),
      getCommissionTrend(start, end),
      getPlacements(),
      getVisits({ since: start.toISOString(), limit: 500 }),
    ]).then(([cls, visitTrend, funnelData, commTrend, placements, recentVisits]) => {
      setClients(cls)
      setFunnel(funnelData)

      // Deduplicate visitTrend by (account_id, user_id, date) — one physical visit per account per day
      const visitSeen = new Set<string>()
      const dedupedVisits = visitTrend.filter((v: any) => {
        const key = `${v.account_id}|${v.user_id}|${String(v.visited_at).slice(0, 10)}`
        if (visitSeen.has(key)) return false
        visitSeen.add(key)
        return true
      })

      // Visit activity buckets — daily for ≤30D, weekly for ≤90D, monthly for 1Y
      const buckets = rangeDays <= 30 ? rangeDays : rangeDays <= 90 ? Math.ceil(rangeDays / 7) : Math.ceil(rangeDays / 30)
      const bucketMs = (rangeDays * 24 * 60 * 60 * 1000) / buckets
      const bucketData: { label: string; visits: number }[] = []
      for (let i = 0; i < buckets; i++) {
        const d = new Date(start.getTime() + i * bucketMs)
        bucketData.push({ label: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }), visits: 0 })
      }
      dedupedVisits.forEach((v: any) => {
        const vt = new Date(v.visited_at).getTime()
        const idx = Math.min(buckets - 1, Math.floor((vt - start.getTime()) / bucketMs))
        if (idx >= 0) bucketData[idx].visits++
      })
      setVisitData(bucketData)
      setVisitCounts({
        total: dedupedVisits.length,
        unique: new Set(dedupedVisits.map((v: any) => v.account_id).filter(Boolean)).size,
      })

      // Commission — bucket by day/week/month depending on range
      const commBuckets: { label: string; commission: number; keyStart: number; keyEnd: number; orders: any[] }[] = []
      const useDaily = rangeDays <= 14
      const useWeekly = rangeDays <= 90 && !useDaily
      if (useDaily) {
        for (let i = 0; i < rangeDays; i++) {
          const d = new Date(start.getTime() + i * 86400_000)
          commBuckets.push({ label: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }), commission: 0, keyStart: d.getTime(), keyEnd: d.getTime() + 86400_000, orders: [] })
        }
      } else if (useWeekly) {
        const weeks = Math.ceil(rangeDays / 7)
        for (let i = 0; i < weeks; i++) {
          const d = new Date(start.getTime() + i * 7 * 86400_000)
          commBuckets.push({ label: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }), commission: 0, keyStart: d.getTime(), keyEnd: d.getTime() + 7 * 86400_000, orders: [] })
        }
      } else {
        const months = Math.ceil(rangeDays / 30)
        for (let i = months - 1; i >= 0; i--) {
          const d = new Date()
          d.setDate(1)
          d.setMonth(d.getMonth() - i)
          const monthStart = d.getTime()
          const monthEnd = new Date(d.getFullYear(), d.getMonth() + 1, 1).getTime()
          commBuckets.push({ label: d.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }), commission: 0, keyStart: monthStart, keyEnd: monthEnd, orders: [] })
        }
      }
      commTrend.forEach((o: any) => {
        const t2 = new Date(o.created_at).getTime()
        const bucket = commBuckets.find(b => t2 >= b.keyStart && t2 < b.keyEnd)
        if (bucket) { bucket.commission += Number(o.commission_amount || 0); bucket.orders.push(o) }
      })
      setCommissionData(commBuckets.map(b => ({ month: b.label, commission: b.commission })))

      // Placements by status (all active, not date-ranged — current state)
      const statusMap2: Record<string, number> = {}
      const brandMap: Record<string, number> = {}
      placements.forEach((p: any) => {
        statusMap2[p.status] = (statusMap2[p.status] || 0) + 1
        if (p.client_slug) brandMap[p.client_slug] = (brandMap[p.client_slug] || 0) + 1
      })
      const STATUS_ORDER: PlacementStatus[] = ['committed', 'ordered', 'on_shelf', 'reordering']
      setPlacementsByStatus(STATUS_ORDER.filter(s => statusMap2[s]).map(s => ({ name: s, value: statusMap2[s] })))
      setPlacementsByBrand(brandMap)

      // Visits by status — grouped for drill-down
      const statusCount: Record<string, number> = {}
      const grouped: Record<string, any[]> = {}
      recentVisits.forEach((v: any) => {
        if (!v.status) return
        statusCount[v.status] = (statusCount[v.status] || 0) + 1
        if (!grouped[v.status]) grouped[v.status] = []
        grouped[v.status].push(v)
      })
      // Sort each group by most recent first
      Object.values(grouped).forEach(arr => arr.sort((a, b) => new Date(b.visited_at).getTime() - new Date(a.visited_at).getTime()))
      setVisitsByStatus(Object.entries(statusCount).map(([status, count]) => ({ status, count })).sort((a, b) => b.count - a.count))
      setVisitsByStatusGrouped(grouped)

      setLoading(false)
    }).catch(() => setLoading(false))
  }, [rangeDays])

  const statusColors: Record<string, string> = {
    committed: t.status.warning,
    ordered: t.status.info,
    on_shelf: t.status.success,
    reordering: t.gold,
  }

  // Derive follow-up groups — deduplicated by account per status group
  const followUpGroups = (['Will Order Soon', 'Needs Follow Up'] as const).map(status => {
    const visits = (visitsByStatusGrouped[status] || [])
      .filter((v: any) => !dismissedIds.has(v.id))
      .map((v: any) => ({ ...v, _status: status }))
    const seen = new Set<string>()
    const deduped = visits.filter((v: any) => {
      if (seen.has(v.account_id)) return false
      seen.add(v.account_id)
      return true
    })
    return { status, color: VISIT_STATUS_COLORS[status], visits: deduped }
  }).filter(g => g.visits.length > 0)

  return (
    <LayoutShell>
      <div style={{ padding: isMobile ? '16px' : '32px 48px', maxWidth: '1440px', margin: '0 auto', width: '100%' }}>

        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '28px', gap: '12px', flexWrap: 'wrap' }}>
          <div>
            <h1 className="page-h1" style={{ fontSize: '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em' }}>Analytics</h1>
            <p style={{ fontSize: '13px', color: t.text.muted, marginTop: '2px' }}>Field activity and performance data</p>
          </div>
          <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
            {DATE_RANGES.map(r => (
              <button key={r.days} onClick={() => setRangeDays(r.days)} style={{
                padding: '7px 14px', borderRadius: '6px', fontSize: '12px', cursor: 'pointer',
                border: `1px solid ${rangeDays === r.days ? t.gold : t.border.default}`,
                backgroundColor: rangeDays === r.days ? t.goldDim : t.bg.card,
                color: rangeDays === r.days ? t.gold : t.text.secondary,
                fontWeight: rangeDays === r.days ? '700' : '400',
                fontFamily: 'inherit',
                transition: 'all 150ms ease',
              }}>
                {r.label}
              </button>
            ))}
          </div>
        </div>

        {/* Funnel stats */}
        {loading ? <StatsSkeleton /> : funnel && (
          <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr 1fr' : 'repeat(4, 1fr)', gap: '16px', marginBottom: '28px' }}>
            <StatCard label="Total Visits" value={visitCounts?.total ?? '—'} color={t.gold} />
            <StatCard label="Placements Created" value={funnel.placementsCreated} color={t.status.success} />
            <StatCard label="Active On Shelf" value={funnel.activeOnShelf} color={t.status.info} subtext="all active placements" />
            <StatCard label="Unique Accounts Visited" value={visitCounts?.unique ?? '—'} color={t.text.secondary} />
          </div>
        )}

        {/* Charts row */}
        <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '20px', marginBottom: '20px' }}>

          {/* Visit trend */}
          <div style={{ ...card, padding: '22px 24px' }}>
            <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '18px' }}>
              Visit Activity
            </div>
            <ResponsiveContainer width="100%" height={180}>
              <BarChart data={visitData} barCategoryGap="30%">
                <CartesianGrid strokeDasharray="3 3" stroke={t.border.subtle} vertical={false} />
                <XAxis dataKey="label" tick={{ fill: t.text.muted, fontSize: 10 }} axisLine={false} tickLine={false} interval={visitData.length <= 14 ? 0 : Math.floor(visitData.length / 7)} />
                <YAxis tick={{ fill: t.text.muted, fontSize: 10 }} axisLine={false} tickLine={false} allowDecimals={false} />
                <Tooltip content={<ChartTooltip />} cursor={{ fill: 'rgba(255,255,255,0.04)' }} />
                <Bar dataKey="visits" name="Visits" fill={t.gold} radius={[3, 3, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Commission trend */}
          <div style={{ ...card, padding: '22px 24px' }}>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', marginBottom: '18px' }}>
              <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
                Commission
              </div>
              <div style={{ fontSize: '10px', color: t.text.muted }}>by order date</div>
            </div>
            <ResponsiveContainer width="100%" height={180}>
              <LineChart data={commissionData}>
                <CartesianGrid strokeDasharray="3 3" stroke={t.border.subtle} vertical={false} />
                <XAxis dataKey="month" tick={{ fill: t.text.muted, fontSize: 10 }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fill: t.text.muted, fontSize: 10 }} axisLine={false} tickLine={false} tickFormatter={v => `$${v}`} />
                <Tooltip content={<ChartTooltip currency />} cursor={{ stroke: 'rgba(212,168,67,0.2)', strokeWidth: 1 }} />
                <Line dataKey="commission" name="Commission" stroke={t.gold} strokeWidth={2}
                  dot={false} activeDot={{ r: 4, fill: t.gold, strokeWidth: 0 }} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Bottom row */}
        <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '20px', marginBottom: '20px' }}>

          {/* Visit outcomes — with drill-down */}
          {visitsByStatus.length > 0 && (
            <div style={{ ...card, padding: '22px 24px' }}>
              <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '16px' }}>
                Visit Outcomes
                <span style={{ fontWeight: '400', textTransform: 'none', marginLeft: '6px', color: t.text.muted, fontSize: '10px' }}>click to see accounts</span>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                {visitsByStatus.map(({ status, count }) => {
                  const color = VISIT_STATUS_COLORS[status] || t.text.muted
                  const max = visitsByStatus[0].count
                  const isOpen = expandedStatus === status
                  const visits = visitsByStatusGrouped[status] || []
                  return (
                    <div key={status}>
                      {/* Status row */}
                      <div
                        onClick={() => setExpandedStatus(isOpen ? null : status)}
                        style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '7px 8px', borderRadius: '7px', cursor: 'pointer', backgroundColor: isOpen ? t.bg.elevated : 'transparent', transition: 'background 150ms ease' }}
                      >
                        <div style={{ color: t.text.muted, flexShrink: 0 }}>
                          {isOpen ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                        </div>
                        <div style={{ width: '130px', fontSize: '12px', color: t.text.secondary, flexShrink: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                          {status}
                        </div>
                        <div style={{ flex: 1, height: '6px', backgroundColor: t.border.default, borderRadius: '3px', overflow: 'hidden' }}>
                          <div style={{ width: `${(count / max) * 100}%`, height: '100%', backgroundColor: color, borderRadius: '3px', transition: 'width 600ms ease' }} />
                        </div>
                        <div className="mono" style={{ fontSize: '12px', color, fontWeight: '700', minWidth: '28px', textAlign: 'right' }}>{count}</div>
                      </div>

                      {/* Drill-down panel */}
                      {isOpen && (
                        <div style={{ marginLeft: '20px', marginBottom: '6px', borderLeft: `2px solid ${color}33`, paddingLeft: '12px' }}>
                          {visits.map((v: any) => (
                            <div key={v.id} style={{ padding: '8px 0', borderBottom: `1px solid ${t.border.subtle}`, display: 'flex', flexDirection: 'column', gap: '3px' }}>
                              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '8px' }}>
                                <div style={{ fontSize: '13px', fontWeight: '600', color: t.text.primary }}>
                                  {v.accounts?.name || 'Unknown Account'}
                                </div>
                                <div style={{ fontSize: '11px', color: t.text.muted, flexShrink: 0 }}>
                                  {formatShortDateMT(v.visited_at)}
                                </div>
                              </div>
                              {v.user_profiles?.name && (
                                <div style={{ fontSize: '11px', color: t.text.muted }}>Rep: {v.user_profiles.name}</div>
                              )}
                              {v.notes && (
                                <div style={{ fontSize: '12px', color: t.text.secondary, lineHeight: 1.4, marginTop: '2px' }}>
                                  {v.notes.length > 120 ? v.notes.slice(0, 120) + '…' : v.notes}
                                </div>
                              )}
                              {v.feedback && (
                                <div style={{ fontSize: '11px', color: t.text.muted, fontStyle: 'italic' }}>
                                  Feedback: {v.feedback.length > 100 ? v.feedback.slice(0, 100) + '…' : v.feedback}
                                </div>
                              )}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  )
                })}
              </div>
            </div>
          )}

          {/* Active placements */}
          {placementsByStatus.length > 0 && (
            <div style={{ ...card, padding: '22px 24px' }}>
              <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '16px' }}>
                Active Placements
              </div>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                {placementsByStatus.map(p => (
                  <div key={p.name} style={{
                    backgroundColor: t.bg.elevated, border: `1px solid ${t.border.default}`,
                    borderRadius: '8px', padding: '16px 20px',
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px', minWidth: '80px',
                  }}>
                    <div className="mono" style={{ fontSize: '24px', fontWeight: '700', color: statusColors[p.name] || t.gold }}>{p.value}</div>
                    <div style={{ fontSize: '10px', color: t.text.muted, textAlign: 'center' }}>{PLACEMENT_STATUS_LABELS[p.name as PlacementStatus] || p.name}</div>
                  </div>
                ))}
              </div>

              {clients.length > 0 && (
                <div style={{ marginTop: '20px', paddingTop: '16px', borderTop: `1px solid ${t.border.subtle}` }}>
                  <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '12px' }}>By Brand</div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    {clients.filter(c => placementsByBrand[c.slug]).map(c => {
                      const logo = clientLogoUrl(c)
                      return (
                        <div key={c.slug} style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                          {logo
                            ? <img src={logo} alt={c.name} style={{ width: 16, height: 16, objectFit: 'contain', borderRadius: '2px', flexShrink: 0 }} />
                            : <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: c.color, flexShrink: 0, margin: '0 4px' }} />
                          }
                          <span style={{ fontSize: '12px', color: t.text.secondary, flex: 1 }}>{c.name}</span>
                          <span className="mono" style={{ fontSize: '12px', color: t.text.muted, fontWeight: '600' }}>{placementsByBrand[c.slug] || 0}</span>
                        </div>
                      )
                    })}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Follow-up action list — grouped by status */}
        {followUpGroups.length > 0 && (
          <div style={{ ...card, padding: '22px 24px' }}>
            <div style={{ fontSize: '11px', fontWeight: '700', color: t.status.warning, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '20px' }}>
              Needs Action
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
              {followUpGroups.map(({ status, color, visits }) => {
                const showAll = showAllByStatus[status] ?? false
                const visible = showAll ? visits : visits.slice(0, 4)
                return (
                  <div key={status}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '10px' }}>
                      <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: color, flexShrink: 0 }} />
                      <span style={{ fontSize: '12px', fontWeight: '700', color }}>{status}</span>
                      <span style={{ fontSize: '11px', color: t.text.muted }}>{visits.length} account{visits.length !== 1 ? 's' : ''}</span>
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fill, minmax(280px, 1fr))', gap: '10px' }}>
                      {visible.map((v: any) => (
                        <div key={v.id} style={{ padding: '12px 14px', borderRadius: '8px', backgroundColor: t.bg.elevated, border: `1px solid ${t.border.default}`, borderLeft: `3px solid ${color}` }}>
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '8px', marginBottom: '4px' }}>
                            <div style={{ fontSize: '13px', fontWeight: '600', color: t.text.primary }}>{v.accounts?.name || '—'}</div>
                            <div style={{ fontSize: '10px', color: t.text.muted, flexShrink: 0 }}>{formatShortDateMT(v.visited_at)}</div>
                          </div>
                          {v.notes && (
                            <div style={{ fontSize: '11px', color: t.text.secondary, lineHeight: 1.4, marginBottom: '4px' }}>
                              {v.notes.length > 80 ? v.notes.slice(0, 80) + '…' : v.notes}
                            </div>
                          )}
                          {v.user_profiles?.name && (
                            <div style={{ fontSize: '10px', color: t.text.muted, marginBottom: '8px' }}>{v.user_profiles.name}</div>
                          )}
                          <div style={{ display: 'flex', gap: '6px' }}>
                            <button onClick={() => setVisitModal({ open: true, accountId: v.account_id, accountName: v.accounts?.name })} style={{
                              flex: 1, padding: '5px 8px', borderRadius: '6px', fontSize: '11px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '4px',
                              border: `1px solid ${t.border.hover}`, backgroundColor: 'transparent', color: t.text.secondary,
                            }}>
                              <MapPin size={11} /> Log Visit
                            </button>
                            <button onClick={() => { setDismissedIds(prev => new Set([...prev, v.id])); clearFollowUp(v.id) }} style={{
                              flex: 1, padding: '5px 8px', borderRadius: '6px', fontSize: '11px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '4px',
                              border: `1px solid rgba(61,186,120,0.3)`, backgroundColor: 'rgba(61,186,120,0.08)', color: '#3dba78',
                            }}>
                              <CheckCircle2 size={11} /> Cleared
                            </button>
                            <button onClick={() => { setDismissedIds(prev => new Set([...prev, v.id])); dismissFollowUp(v.id) }} style={{
                              flex: 1, padding: '5px 8px', borderRadius: '6px', fontSize: '11px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '4px',
                              border: `1px solid ${t.border.default}`, backgroundColor: 'transparent', color: t.text.muted,
                            }}>
                              <MinusCircle size={11} /> Disregard
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                    {visits.length > 4 && (
                      <button
                        onClick={() => setShowAllByStatus(prev => ({ ...prev, [status]: !showAll }))}
                        style={{ marginTop: '10px', width: '100%', padding: '8px', borderRadius: '8px', fontSize: '12px', border: `1px solid ${t.border.default}`, backgroundColor: 'transparent', color: t.text.muted, cursor: 'pointer' }}
                      >
                        {showAll ? 'Show less' : `+ ${visits.length - 4} more`}
                      </button>
                    )}
                  </div>
                )
              })}
            </div>
          </div>
        )}

      </div>
      {profile && (
        <VisitLogModal
          isOpen={visitModal.open}
          onClose={() => setVisitModal({ open: false })}
          onSuccess={() => setVisitModal({ open: false })}
          userId={profile.id}
          defaultAccountId={visitModal.accountId}
          defaultAccountName={visitModal.accountName}
          isMobile={false}
        />
      )}
    </LayoutShell>
  )
}

'use client'
import { useState, useEffect, useCallback } from 'react'
import { ChevronLeft, ChevronRight, Plus, X, QrCode, Download, Users } from 'lucide-react'
import LayoutShell from '../layout-shell'
import ConfirmModal from '../components/ConfirmModal'
import { getEvents, getClients, createEvent, deleteEvent, getCampaigns } from '../lib/data'
import { getSupabase } from '../lib/supabase'
import { t, card, btnPrimary, btnSecondary, inputStyle, labelStyle, selectStyle } from '../lib/theme'
import { formatShortDateMT, todayMT } from '../lib/formatters'
import { EVENT_TYPE_LABELS } from '../lib/constants'
import type { Client } from '../lib/types'

const EVENT_TYPE_COLORS: Record<string, string> = {
  tasting: '#d4a843', brand_dinner: '#f43f5e', meeting: '#4a9eff', planned_stop: '#3dba78',
  milestone: '#a78bfa', training: '#e89a2e', other: '#6b6966',
}

const CAMPAIGN_COLOR = '#a78bfa'
const MILESTONE_COLOR = '#f472b6'

const CATEGORY_OPTIONS = [
  'All', 'Tasting', 'Dinner', 'Meeting', 'Demo', 'Training', 'Event', 'Campaign', 'Milestone',
]

function getDaysInMonth(year: number, month: number) {
  return new Date(year, month + 1, 0).getDate()
}
function getFirstDayOfMonth(year: number, month: number) {
  return new Date(year, month, 1).getDay()
}

export default function CalendarPage() {
  const today = new Date()
  const [viewMonth, setViewMonth] = useState(today.getMonth())
  const [viewYear, setViewYear] = useState(today.getFullYear())
  const [events, setEvents] = useState<any[]>([])
  const [campaigns, setCampaigns] = useState<any[]>([])
  const [clients, setClients] = useState<Client[]>([])
  const [users, setUsers] = useState<any[]>([])
  const [selectedDay, setSelectedDay] = useState<number | null>(null)
  const [showCreate, setShowCreate] = useState(false)
  const [form, setForm] = useState({ title: '', event_type: 'tasting', client_slug: '', start_time: todayMT() + 'T10:00', end_time: '', notes: '', url: '', status: 'planned' })
  const [isMobile, setIsMobile] = useState(false)
  const [qrEventId, setQrEventId] = useState<string | null>(null)
  const [qrDataUrl, setQrDataUrl] = useState<string | null>(null)
  const [qrResponseCount, setQrResponseCount] = useState<number | null>(null)
  const [deleteEventTarget, setDeleteEventTarget] = useState<any>(null)

  // Filters
  const [filterUser, setFilterUser] = useState('all')
  const [filterClient, setFilterClient] = useState('all')
  const [filterCategory, setFilterCategory] = useState('All')

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  const load = useCallback(async () => {
    const monthStart = new Date(viewYear, viewMonth, 1).toISOString()
    const monthEnd = new Date(viewYear, viewMonth + 1, 0, 23, 59, 59).toISOString()
    const [evs, cls, camps] = await Promise.all([
      getEvents({ since: monthStart, until: monthEnd }),
      getClients(),
      getCampaigns().catch(() => []),
    ])
    setEvents(evs)
    setClients(cls)
    setCampaigns(camps)
  }, [viewMonth, viewYear])

  useEffect(() => { load() }, [load])

  // Load users for filter
  useEffect(() => {
    const sb = getSupabase()
    sb.from('user_profiles').select('id, name, full_name').in('role', ['owner', 'rep'])
      .then(({ data }) => setUsers(data || []))
      .catch(() => {})
  }, [])

  const daysInMonth = getDaysInMonth(viewYear, viewMonth)
  const firstDay = getFirstDayOfMonth(viewYear, viewMonth)
  const monthName = new Date(viewYear, viewMonth).toLocaleDateString('en-US', { month: 'long', year: 'numeric' })

  // Build campaign entries for the month
  const campaignEntries: { dateStr: string; title: string; color: string; isCampaign: boolean; isMilestone: boolean; clientSlug: string }[] = []
  campaigns.forEach((camp: any) => {
    const color = camp.clients?.color || CAMPAIGN_COLOR
    const clientSlug = camp.client_slug || ''
    // Campaign start/end as entries
    if (camp.start_date) {
      const d = camp.start_date.slice(0, 10)
      const [y, m] = d.split('-').map(Number)
      if (y === viewYear && m - 1 === viewMonth) {
        campaignEntries.push({ dateStr: d, title: `📣 ${camp.name}`, color, isCampaign: true, isMilestone: false, clientSlug })
      }
    }
    // Milestones
    if (camp.campaign_milestones) {
      camp.campaign_milestones.forEach((ms: any) => {
        if (ms.due_date) {
          const d = ms.due_date.slice(0, 10)
          const [y, m] = d.split('-').map(Number)
          if (y === viewYear && m - 1 === viewMonth) {
            campaignEntries.push({ dateStr: d, title: ms.title, color: MILESTONE_COLOR, isCampaign: false, isMilestone: true, clientSlug })
          }
        }
      })
    }
  })

  function getEventsForDay(day: number) {
    const dateStr = `${viewYear}-${String(viewMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`
    let evs = events.filter(e => e.start_time?.startsWith(dateStr))

    // Apply filters
    if (filterUser !== 'all') {
      evs = evs.filter(e => e.user_id === filterUser || e.created_by === filterUser)
    }
    if (filterClient !== 'all') {
      evs = evs.filter(e => e.client_slug === filterClient)
    }
    if (filterCategory !== 'All') {
      const cat = filterCategory.toLowerCase()
      evs = evs.filter(e => {
        const type = (e.event_type || '').toLowerCase()
        return type === cat || type.includes(cat)
      })
    }

    const camps = filterCategory === 'All' || filterCategory === 'Campaign'
      ? campaignEntries.filter(ce => ce.dateStr === dateStr && !ce.isMilestone && (filterClient === 'all' || ce.clientSlug === filterClient || ce.clientSlug === ''))
      : []
    const milestones = filterCategory === 'All' || filterCategory === 'Milestone'
      ? campaignEntries.filter(ce => ce.dateStr === dateStr && ce.isMilestone && (filterClient === 'all' || ce.clientSlug === filterClient || ce.clientSlug === ''))
      : []

    return { evs, camps, milestones }
  }

  const selectedDateStr = selectedDay
    ? `${viewYear}-${String(viewMonth + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`
    : null
  const selectedDayData = selectedDay ? getEventsForDay(selectedDay) : { evs: [], camps: [], milestones: [] }
  const allSelectedItems = [
    ...selectedDayData.evs,
    ...selectedDayData.camps.map(c => ({ ...c, _isCampaignEntry: true })),
    ...selectedDayData.milestones.map(m => ({ ...m, _isMilestoneEntry: true })),
  ]

  async function generateQr(eventId: string) {
    if (qrEventId === eventId) { setQrEventId(null); setQrDataUrl(null); setQrResponseCount(null); return }
    setQrEventId(eventId)
    setQrDataUrl(null)
    setQrResponseCount(null)
    const url = `${window.location.origin}/taste/${eventId}`
    const QRCode = (await import('qrcode')).default
    const dataUrl = await QRCode.toDataURL(url, { width: 240, margin: 2, color: { dark: '#d4a843', light: '#1a1916' } })
    setQrDataUrl(dataUrl)
    const sb = getSupabase()
    const { count } = await sb.from('tasting_consumers').select('id', { count: 'exact', head: true }).eq('event_id', eventId)
    setQrResponseCount(count || 0)
  }

  function downloadQr(eventTitle: string) {
    if (!qrDataUrl) return
    const a = document.createElement('a')
    a.href = qrDataUrl
    a.download = `qr-${eventTitle.replace(/[^a-z0-9]/gi, '-').toLowerCase()}.png`
    a.click()
  }

  async function handleCreate() {
    await createEvent({ ...form, start_time: new Date(form.start_time).toISOString(), end_time: form.end_time ? new Date(form.end_time).toISOString() : undefined } as any)
    setShowCreate(false)
    setForm({ title: '', event_type: 'tasting', client_slug: '', start_time: todayMT() + 'T10:00', end_time: '', notes: '', url: '', status: 'planned' })
    load()
  }

  const pillStyle = (active: boolean): React.CSSProperties => ({
    padding: '5px 12px', borderRadius: '16px', fontSize: '12px', cursor: 'pointer',
    whiteSpace: 'nowrap',
    backgroundColor: active ? t.goldDim : t.bg.card,
    color: active ? t.gold : t.text.secondary,
    fontWeight: active ? '600' : '400',
    border: `1px solid ${active ? t.gold : t.border.default}`,
  })

  return (
    <LayoutShell>
      <div style={{ padding: isMobile ? '16px' : '32px 48px', maxWidth: '1300px', margin: '0 auto', width: '100%' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px', flexWrap: 'wrap', gap: '10px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <h1 style={{ fontSize: isMobile ? '18px' : '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em' }}>{monthName}</h1>
            <div style={{ display: 'flex', gap: '4px' }}>
              <button onClick={() => { if (viewMonth === 0) { setViewMonth(11); setViewYear(y => y - 1) } else setViewMonth(m => m - 1) }}
                style={{ background: 'none', border: `1px solid ${t.border.default}`, borderRadius: '6px', color: t.text.secondary, cursor: 'pointer', padding: '5px 9px' }}>
                <ChevronLeft size={14} />
              </button>
              <button onClick={() => { if (viewMonth === 11) { setViewMonth(0); setViewYear(y => y + 1) } else setViewMonth(m => m + 1) }}
                style={{ background: 'none', border: `1px solid ${t.border.default}`, borderRadius: '6px', color: t.text.secondary, cursor: 'pointer', padding: '5px 9px' }}>
                <ChevronRight size={14} />
              </button>
            </div>
          </div>
          {!isMobile && (
            <button onClick={() => setShowCreate(true)} style={btnPrimary}><Plus size={16} /> Add Event</button>
          )}
        </div>

        {/* Filter bar */}
        <div style={{
          display: 'flex', gap: '8px', marginBottom: '16px',
          overflowX: 'auto', paddingBottom: '4px',
          msOverflowStyle: 'none', scrollbarWidth: 'none',
        }}>
          {/* User filter */}
          {users.length > 0 && (
            <select
              value={filterUser}
              onChange={e => setFilterUser(e.target.value)}
              style={{ ...pillStyle(filterUser !== 'all'), paddingRight: '20px', appearance: 'none' as const, outline: 'none' }}
            >
              <option value="all">All Users</option>
              {users.map(u => <option key={u.id} value={u.id}>{u.name || u.full_name}</option>)}
            </select>
          )}

          {/* Client filter */}
          <select
            value={filterClient}
            onChange={e => setFilterClient(e.target.value)}
            style={{ ...pillStyle(filterClient !== 'all'), paddingRight: '20px', appearance: 'none' as const, outline: 'none' }}
          >
            <option value="all">All Brands</option>
            {clients.map(c => <option key={c.slug} value={c.slug}>{c.name}</option>)}
          </select>

          {/* Category filter pills */}
          {CATEGORY_OPTIONS.map(cat => (
            <button key={cat} onClick={() => setFilterCategory(cat)} style={pillStyle(filterCategory === cat)}>
              {cat}
            </button>
          ))}

          {isMobile && (
            <button onClick={() => setShowCreate(true)} style={{ ...pillStyle(false), backgroundColor: t.goldDim, color: t.gold, border: `1px solid ${t.gold}`, flexShrink: 0 }}>
              <Plus size={12} style={{ display: 'inline', verticalAlign: 'middle', marginRight: '4px' }} />Add
            </button>
          )}
        </div>

        {/* Day headers */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '1px', marginBottom: '1px' }}>
          {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
            <div key={d} style={{ padding: isMobile ? '4px 2px' : '8px', textAlign: 'center', fontSize: isMobile ? '9px' : '11px', fontWeight: '600', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.06em' }}>{d}</div>
          ))}
        </div>

        {/* Calendar grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '1px', backgroundColor: t.border.subtle }}>
          {/* Empty cells before first day */}
          {[...Array(firstDay)].map((_, i) => (
            <div key={`empty-${i}`} style={{ backgroundColor: t.bg.page, minHeight: isMobile ? '48px' : '80px' }} />
          ))}
          {/* Day cells */}
          {[...Array(daysInMonth)].map((_, i) => {
            const day = i + 1
            const isToday = day === today.getDate() && viewMonth === today.getMonth() && viewYear === today.getFullYear()
            const { evs: dayEvents, camps: dayCamps, milestones: dayMilestones } = getEventsForDay(day)
            const allDayItems = [...dayEvents, ...dayCamps, ...dayMilestones]
            const isSelected = selectedDay === day
            return (
              <div key={day} onClick={() => setSelectedDay(day === selectedDay ? null : day)} style={{
                backgroundColor: isSelected ? t.bg.card : t.bg.page,
                minHeight: isMobile ? '48px' : '80px',
                padding: isMobile ? '4px' : '8px',
                cursor: 'pointer',
                transition: 'background 150ms ease',
              }}>
                <div style={{
                  width: isMobile ? 20 : 26, height: isMobile ? 20 : 26, borderRadius: '50%',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: isMobile ? '11px' : '13px', fontWeight: isToday ? '700' : '400',
                  backgroundColor: isToday ? t.gold : 'transparent',
                  color: isToday ? '#0f0f0d' : t.text.primary,
                  marginBottom: '2px',
                }}>
                  {day}
                </div>
                {!isMobile && allDayItems.slice(0, 3).map((e: any, idx: number) => {
                  if (e._isCampaignEntry || e._isMilestoneEntry) {
                    return (
                      <div key={`camp-${idx}`} style={{
                        fontSize: '10px', padding: '1px 5px', borderRadius: '4px', marginBottom: '2px',
                        backgroundColor: e.color + '20',
                        color: e.color,
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                        fontWeight: '500',
                      }}>
                        {e.title}
                      </div>
                    )
                  }
                  const client = clients.find(c => c.slug === e.client_slug)
                  return (
                    <div key={e.id} style={{
                      fontSize: '10px', padding: '1px 5px', borderRadius: '4px', marginBottom: '2px',
                      backgroundColor: (client?.color || EVENT_TYPE_COLORS[e.event_type] || t.gold) + '20',
                      color: client?.color || EVENT_TYPE_COLORS[e.event_type] || t.gold,
                      overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                      fontWeight: '500',
                    }}>
                      {e.title}
                    </div>
                  )
                })}
                {isMobile && allDayItems.length > 0 && (
                  <div style={{ display: 'flex', gap: '2px', flexWrap: 'wrap', marginTop: '2px' }}>
                    {allDayItems.slice(0, 3).map((e: any, idx: number) => {
                      const color = e._isCampaignEntry || e._isMilestoneEntry
                        ? e.color
                        : (clients.find(c => c.slug === e.client_slug)?.color || EVENT_TYPE_COLORS[e.event_type] || t.gold)
                      return <div key={idx} style={{ width: 6, height: 6, borderRadius: '50%', backgroundColor: color }} />
                    })}
                    {allDayItems.length > 3 && <div style={{ fontSize: '8px', color: t.text.muted }}>+{allDayItems.length - 3}</div>}
                  </div>
                )}
                {!isMobile && allDayItems.length > 3 && <div style={{ fontSize: '10px', color: t.text.muted }}>+{allDayItems.length - 3} more</div>}
              </div>
            )
          })}
        </div>

        {/* Selected day events */}
        {selectedDay && allSelectedItems.length > 0 && (
          <div style={{ ...card, marginTop: '20px', padding: isMobile ? '16px' : '20px 24px' }}>
            <h3 style={{ fontSize: '14px', fontWeight: '600', color: t.text.primary, marginBottom: '14px' }}>
              {new Date(viewYear, viewMonth, selectedDay).toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </h3>
            {allSelectedItems.map((e: any, idx: number) => {
              if (e._isCampaignEntry || e._isMilestoneEntry) {
                return (
                  <div key={`camp-${idx}`} style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px 0', borderBottom: `1px solid ${t.border.subtle}` }}>
                    <div style={{ width: 10, height: 10, borderRadius: '50%', backgroundColor: e.color, flexShrink: 0 }} />
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: '14px', fontWeight: '500', color: t.text.primary }}>{e.title}</div>
                      <div style={{ fontSize: '11px', color: t.text.muted }}>{e.isMilestone ? 'Campaign Milestone' : 'Campaign'}</div>
                    </div>
                  </div>
                )
              }
              const client = clients.find(c => c.slug === e.client_slug)
              const color = client?.color || EVENT_TYPE_COLORS[e.event_type] || t.gold
              const isTasting = e.event_type === 'tasting'
              const isQrOpen = qrEventId === e.id
              return (
                <div key={e.id} style={{ borderBottom: `1px solid ${t.border.subtle}` }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px 0' }}>
                    <div style={{ width: 10, height: 10, borderRadius: '50%', backgroundColor: color, flexShrink: 0 }} />
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: '14px', fontWeight: '500', color: t.text.primary }}>{e.title}</div>
                      <div style={{ fontSize: '11px', color: t.text.muted }}>
                        {EVENT_TYPE_LABELS[e.event_type as keyof typeof EVENT_TYPE_LABELS]}
                        {e.accounts?.name && ` · ${e.accounts.name}`}
                        {client && ` · ${client.name}`}
                      </div>
                      {e.url && <a href={e.url} target="_blank" rel="noopener noreferrer" onClick={ev => ev.stopPropagation()} style={{ fontSize: '11px', color: t.gold, textDecoration: 'none', marginTop: '2px', display: 'block', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>🔗 RSVP / Link</a>}
                    </div>
                    {isTasting && (
                      <button onClick={() => generateQr(e.id)} title="Generate QR Code" style={{ background: isQrOpen ? t.goldDim : 'none', border: isQrOpen ? `1px solid ${t.border.gold}` : 'none', borderRadius: '6px', color: isQrOpen ? t.gold : t.text.muted, cursor: 'pointer', padding: '4px 8px', display: 'flex', alignItems: 'center', gap: '4px', fontSize: '11px', fontWeight: '600' }}>
                        <QrCode size={14} /> QR
                      </button>
                    )}
                    <button onClick={() => setDeleteEventTarget(e)} style={{ background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer', padding: '4px' }}>
                      <X size={14} />
                    </button>
                  </div>
                  {isTasting && isQrOpen && (
                    <div style={{ paddingBottom: '12px', display: 'flex', alignItems: 'center', gap: '16px', flexWrap: 'wrap' }}>
                      {qrDataUrl ? (
                        <>
                          <img src={qrDataUrl} alt="QR Code" style={{ width: 120, height: 120, borderRadius: '8px', border: `1px solid ${t.border.default}` }} />
                          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                            {qrResponseCount !== null && (
                              <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', color: t.text.secondary }}>
                                <Users size={13} /> <span><strong style={{ color: t.text.primary }}>{qrResponseCount}</strong> response{qrResponseCount !== 1 ? 's' : ''}</span>
                              </div>
                            )}
                            <button onClick={() => downloadQr(e.title)} style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '12px', fontWeight: '600', color: t.gold, backgroundColor: t.goldDim, border: `1px solid ${t.border.gold}`, borderRadius: '6px', padding: '6px 12px', cursor: 'pointer' }}>
                              <Download size={13} /> Download QR
                            </button>
                          </div>
                        </>
                      ) : (
                        <div style={{ fontSize: '12px', color: t.text.muted }}>Generating...</div>
                      )}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        )}

        {/* Create event modal */}
        {showCreate && (
          <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '20px' }}>
            <div style={{ backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`, borderRadius: '16px', padding: '28px', width: '100%', maxWidth: '480px', maxHeight: '90vh', overflowY: 'auto' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                <h3 style={{ fontSize: '17px', fontWeight: '600', color: t.text.primary }}>New Event</h3>
                <button onClick={() => setShowCreate(false)} style={{ background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer' }}><X size={18} /></button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div><label style={labelStyle}>Title</label><input type="text" value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} placeholder="Event name..." style={inputStyle} /></div>
                <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '10px' }}>
                  <div><label style={labelStyle}>Type</label>
                    <select value={form.event_type} onChange={e => setForm(f => ({ ...f, event_type: e.target.value }))} style={selectStyle}>
                      {Object.entries(EVENT_TYPE_LABELS).map(([v, l]) => <option key={v} value={v}>{l}</option>)}
                    </select>
                  </div>
                  <div><label style={labelStyle}>Brand</label>
                    <select value={form.client_slug} onChange={e => setForm(f => ({ ...f, client_slug: e.target.value }))} style={selectStyle}>
                      <option value="">No brand</option>
                      {clients.map(c => <option key={c.slug} value={c.slug}>{c.name}</option>)}
                    </select>
                  </div>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                  <div><label style={labelStyle}>Start</label><input type="datetime-local" value={form.start_time} onChange={e => setForm(f => ({ ...f, start_time: e.target.value }))} style={{ ...inputStyle, boxSizing: 'border-box' }} /></div>
                  <div><label style={labelStyle}>End (optional)</label><input type="datetime-local" value={form.end_time} onChange={e => setForm(f => ({ ...f, end_time: e.target.value }))} style={{ ...inputStyle, boxSizing: 'border-box' }} /></div>
                </div>
                <div><label style={labelStyle}>Notes</label><textarea value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} rows={2} style={{ ...inputStyle, resize: 'none' }} /></div>
                <div><label style={labelStyle}>URL / RSVP Link (optional)</label><input type="url" value={form.url} onChange={e => setForm(f => ({ ...f, url: e.target.value }))} placeholder="https://..." style={inputStyle} /></div>
              </div>
              <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '20px' }}>
                <button onClick={() => setShowCreate(false)} style={btnSecondary}>Cancel</button>
                <button onClick={handleCreate} disabled={!form.title} style={{ ...btnPrimary, opacity: !form.title ? 0.6 : 1 }}>Save Event</button>
              </div>
            </div>
          </div>
        )}
      </div>
      <ConfirmModal
        isOpen={!!deleteEventTarget}
        onClose={() => setDeleteEventTarget(null)}
        onConfirm={async () => {
          if (!deleteEventTarget) return
          await deleteEvent(deleteEventTarget.id)
          setDeleteEventTarget(null)
          if (qrEventId === deleteEventTarget.id) { setQrEventId(null); setQrDataUrl(null) }
          load()
        }}
        title="Delete Event"
        message={`Delete "${deleteEventTarget?.title}"? This cannot be undone.`}
        confirmLabel="Delete"
        danger
      />
    </LayoutShell>
  )
}

