interface FormState {
  account_id: string
  account_name: string
  client_slugs: string[]
  visited_at: string
  status: VisitStatus
  notes: string
  client_notes: Record<string, string>
  tastings: TastingEntry[]
  followup_days: number | null
  create_checkin: boolean
}

const emptyForm = (defaultDate: string): FormState => ({
  account_id: '',
  account_name: '',
  client_slugs: [],
  visited_at: defaultDate,
  status: 'General Check-In',
  notes: '',
  client_notes: {},
  tastings: [],
  followup_days: null,
  create_checkin: false,
})

export default function VisitLogModal({
  isOpen, onClose, onSuccess, userId, defaultAccountId, defaultAccountName, defaultClientSlugs, isMobile,
}: Props) {
  const [form, setForm] = useState<FormState>(emptyForm(todayMT()))
  const [clients, setClients] = useState<Client[]>([])
  const [products, setProducts] = useState<Record<string, Product[]>>({})
  const [accountSearch, setAccountSearch] = useState('')
  const [accountResults, setAccountResults] = useState<Account[]>([])
  const [showAccountSearch, setShowAccountSearch] = useState(!defaultAccountId)
  const [showAddAccountModal, setShowAddAccountModal] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [saved, setSaved] = useState(false)
  const [placements, setPlacements] = useState<PlacementEntry[]>([])
  const [showPlacements, setShowPlacements] = useState(false)
  const searchRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (!isOpen) return
    getClients().then(setClients).catch(() => {})
  }, [isOpen])

  function ensureProducts(slug: string) {
    if (!slug || products[slug]) return
    getProducts(slug).then(prods => setProducts(prev => ({ ...prev, [slug]: prods }))).catch(() => {})
  }

  useEffect(() => {
    form.client_slugs.forEach(ensureProducts)
  }, [form.client_slugs])

  // Load products for all clients when the placement panel opens
  useEffect(() => {
    if (!showPlacements) return
    clients.forEach(c => ensureProducts(c.slug))
  }, [showPlacements, clients])

  useEffect(() => {
    if (!accountSearch || accountSearch.length < 2) { setAccountResults([]); return }
    getAccounts({ search: accountSearch, limit: 8 })
      .then(res => setAccountResults(res.filter((a: Account, i: number, arr: Account[]) => arr.findIndex((x: Account) => x.id === a.id) === i)))
      .catch(() => {})
  }, [accountSearch])

  useEffect(() => {
    if (!isOpen) { setSaved(false); setError(''); return }
    const d = todayMT()
    setForm({
      ...emptyForm(d),
      account_id: defaultAccountId || '',
      account_name: defaultAccountName || '',
      client_slugs: defaultClientSlugs || [],
      followup_days: null,
      create_checkin: false,
    })
    setPlacements([])
    setShowPlacements(false)
    if (defaultAccountId) setShowAccountSearch(false)
    else setShowAccountSearch(true)
  }, [isOpen, defaultAccountId, defaultAccountName, defaultClientSlugs])

  function selectAccount(acc: Account) {
    const slugs = acc.account_clients?.map(ac => ac.client_slug) || []
    setForm(f => ({
      ...f,
      account_id: acc.id,
      account_name: acc.name,
      client_slugs: slugs.length > 0 && f.client_slugs.length === 0 ? slugs : f.client_slugs,
    }))
    setShowAccountSearch(false)
    setAccountSearch('')
    setAccountResults([])
  }

  function toggleClient(slug: string) {
    setForm(f => {
      const slugs = f.client_slugs.includes(slug)
        ? f.client_slugs.filter(s => s !== slug)
        : [...f.client_slugs, slug]
      const tastings = slugs.map(s =>
        f.tastings.find(t => t.clientSlug === s) || { clientSlug: s, products: [], notes: '' }
      )
      return { ...f, client_slugs: slugs, tastings }
    })
  }

  function toggleTastingProduct(clientSlug: string, productName: string) {
    setForm(f => ({
      ...f,
      tastings: f.tastings.map(t =>
        t.clientSlug !== clientSlug ? t : {
          ...t,
          products: t.products.includes(productName)
            ? t.products.filter(p => p !== productName)
            : [...t.products, productName],
        }
      ),
    }))
  }

  function updateTasting(clientSlug: string, value: string) {
    setForm(f => ({
      ...f,
      tastings: f.tastings.map(t => t.clientSlug !== clientSlug ? t : { ...t, notes: value }),
    }))
  }

  async function handleSubmit(e: React.SyntheticEvent) {
    e.preventDefault()
    setError('')
    if (!form.account_id) { setError('Please select an account.'); return }
    if (!form.visited_at) { setError('Please enter a visit date.'); return }
    if (isFutureDate(form.visited_at)) { setError('Visit date cannot be in the future.'); return }

    // Build per-client notes that include tasting details for that client only
    const clientNotesWithTasting: Record<string, string> = { ...form.client_notes }
    form.tastings
      .filter(t => t.products.length > 0 || t.notes)
      .forEach(t => {
        const parts = [
          t.products.length > 0 ? `Tasted: ${t.products.join(', ')}` : '',
          t.notes || '',
        ].filter(Boolean).join(' | ')
        const existing = clientNotesWithTasting[t.clientSlug] || ''
        clientNotesWithTasting[t.clientSlug] = [existing, parts].filter(Boolean).join('\n')
      })

    const followupNote = form.followup_days
      ? `Follow up in ${form.followup_days} days`
      : form.create_checkin ? 'General check-in reminder' : undefined

    setSaving(true)
    try {
      let resolvedUserId = userId
      if (!resolvedUserId) {
        const { data: { user } } = await getSupabase().auth.getUser()
        resolvedUserId = user?.id
      }
      if (!resolvedUserId) { setError('Not signed in.'); return }
      await logVisit({
        account_id: form.account_id,
        user_id: resolvedUserId,
        client_slugs: form.client_slugs,
        visited_at: saveDateMT(form.visited_at),
        status: form.status,
        notes: form.notes || undefined,
        client_notes: Object.keys(clientNotesWithTasting).length > 0 ? clientNotesWithTasting : undefined,
        create_followup: !!(form.followup_days || form.create_checkin),
        followup_note: followupNote,
      })

      // Save any placements added during the visit
      const validPlacements = placements.filter(p => p.product_name.trim() && p.client_slug)
      await Promise.all(validPlacements.map(p => createPlacement({
        account_id: form.account_id,
        client_slug: p.client_slug,
        product_name: p.product_name.trim(),
        placement_type: p.placement_type,
        status: p.status,
        shelf_count: p.shelf_count ? parseInt(p.shelf_count) : undefined,
        price_point: p.price_point ? parseFloat(p.price_point) : undefined,
        notes: p.notes || undefined,
        shelf_date: saveDateMT(form.visited_at),
      })))

      setSaved(true)
      setTimeout(() => { onClose(); onSuccess?.() }, 1200)
    } catch (err: any) {
      setError(err.message || 'Failed to log visit.')
    } finally {
      setSaving(false)
    }
  }

  if (!isOpen) return null

  const statusOptions: { value: VisitStatus; color: string }[] = [
    { value: 'Just Ordered',     color: t.status.success },
    { value: 'Will Order Soon',  color: t.status.warning },
    { value: 'New Placement',    color: t.gold },
    { value: 'Menu Feature Won', color: t.status.success },
    { value: 'Needs Follow Up',  color: t.status.info },
    { value: 'Not Interested',   color: t.status.danger },
    { value: 'General Check-In', color: t.text.muted },
  ]

  const content = (
    <div style={{ padding: isMobile ? '0 16px 24px' : '0' }}>
      {isMobile && (
        <div style={{ display: 'flex', justifyContent: 'center', padding: '12px 0 8px' }}>
          <div style={{ width: 36, height: 4, borderRadius: 2, backgroundColor: t.border.hover }} />
        </div>
      )}

      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: isMobile ? '0 0 16px' : '28px 28px 0',
        ...(isMobile ? {} : { paddingBottom: '20px', borderBottom: `1px solid ${t.border.default}` }),
      }}>
        <div>
          <h2 style={{ fontSize: '18px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.01em' }}>Log a Visit</h2>
          {saved && <p style={{ fontSize: '12px', color: t.status.success }}>Visit logged!</p>}
        </div>
        <button onClick={onClose} style={{ background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer', padding: '6px' }}>
          <X size={20} />
        </button>
      </div>

      {saved && (
        <div style={{ padding: isMobile ? '32px 0' : '40px 28px', textAlign: 'center' }}>
          <div style={{
            width: 64, height: 64, borderRadius: '50%',
            backgroundColor: t.status.successBg, border: `2px solid ${t.status.success}`,
            display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px',
          }}>
            <Check size={32} color={t.status.success} />
          </div>
          <div style={{ fontSize: '18px', fontWeight: '600', color: t.text.primary }}>Visit Logged!</div>
          <div style={{ fontSize: '13px', color: t.text.muted, marginTop: '6px' }}>
            {form.account_name} · {form.status}
          </div>
        </div>
      )}

      {!saved && (
        <form onSubmit={handleSubmit} style={{ padding: isMobile ? '0' : '20px 28px 28px' }}>

          {/* Account */}
          <Section label="Account">
            {!showAccountSearch && form.account_name ? (
              <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '10px 14px', backgroundColor: t.bg.input,
                border: `1px solid ${t.border.default}`, borderRadius: '8px',
              }}>
                <span style={{ color: t.text.primary, fontSize: '15px' }}>{form.account_name}</span>
                <button type="button" onClick={() => { setShowAccountSearch(true); setForm(f => ({ ...f, account_id: '', account_name: '' })) }}
                  style={{ background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer', fontSize: '12px' }}>
                  Change
                </button>
              </div>
            ) : (
              <div style={{ position: 'relative' }}>
                <div style={{ position: 'relative' }}>
                  <Search size={14} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: t.text.muted }} />
                  <input
                    ref={searchRef}
                    type="text"
                    value={accountSearch}
                    onChange={e => setAccountSearch(e.target.value)}
                    placeholder="Search accounts..."
                    autoFocus
                    style={{ ...inputStyle, paddingLeft: '36px' }}
                  />
                </div>
                {accountResults.length > 0 && (
                  <div style={{
                    position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 10,
                    backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`,
                    borderRadius: '8px', marginTop: '4px', overflow: 'hidden',
                    boxShadow: '0 8px 24px rgba(0,0,0,0.4)',
                  }}>
                    {accountResults.map(acc => (
                      <button key={acc.id} type="button" onClick={() => selectAccount(acc)}
                        style={{
                          display: 'block', width: '100%', textAlign: 'left',
                          padding: '10px 14px', background: 'none', border: 'none',
                          color: t.text.primary, cursor: 'pointer', fontSize: '14px',
                          borderBottom: `1px solid ${t.border.subtle}`,
                        }}>
                        <div style={{ fontWeight: '500' }}>{acc.name}</div>
                        {acc.address && <div style={{ fontSize: '12px', color: t.text.muted }}>{acc.address}</div>}
                      </button>
                    ))}
                  </div>
                )}
                <button type="button" onClick={() => setShowAddAccountModal(true)} style={{
                  marginTop: '8px', fontSize: '12px', color: t.gold, background: 'none', border: 'none',
                  cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px', padding: '2px 0',
                }}>
                  <Plus size={13} /> Create new account
                </button>
              </div>
            )}
          </Section>

          {/* Date */}
          <Section label="Visit Date">
            <input
              type="date"
              value={form.visited_at}
              max={todayMT()}
              onChange={e => setForm(f => ({ ...f, visited_at: e.target.value }))}
              style={inputStyle}
            />
          </Section>

          {/* Brands */}
          {clients.length > 0 && (
            <Section label="Brands (select all that apply)">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                {clients.map(c => {
                  const selected = form.client_slugs.includes(c.slug)
                  return (
                    <button key={c.slug} type="button" onClick={() => toggleClient(c.slug)} style={{
                      padding: '7px 14px', borderRadius: '20px',
                      border: `1px solid ${selected ? c.color : t.border.default}`,
                      backgroundColor: selected ? (c.color + '20') : 'transparent',
                      color: selected ? c.color : t.text.secondary,
                      fontSize: '13px', fontWeight: selected ? '600' : '400',
                      cursor: 'pointer', transition: 'all 150ms ease',
                    }}>
                      {c.name}
                    </button>
                  )
                })}
              </div>
            </Section>
          )}

          {/* Outcome */}
          <Section label="Outcome">
            <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '6px' }}>
              {statusOptions.map(s => (
                <button key={s.value} type="button" onClick={() => setForm(f => ({ ...f, status: s.value }))}
                  style={{
                    padding: '9px 12px', borderRadius: '8px',
                    border: `1px solid ${form.status === s.value ? s.color : t.border.default}`,
                    backgroundColor: form.status === s.value ? (s.color + '15') : 'transparent',
                    color: form.status === s.value ? s.color : t.text.secondary,
                    fontSize: '12.5px', fontWeight: form.status === s.value ? '600' : '400',
                    cursor: 'pointer', textAlign: 'left', transition: 'all 120ms ease',
                  }}>
                  {s.value}
                </button>
              ))}
            </div>
          </Section>

          {/* Notes — per-brand when multiple brands selected */}
          {form.client_slugs.length > 1 ? (
            <Section label="Notes (per brand)">
              <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '10px' }}>
                Each brand's client portal only shows notes written for that brand.
              </div>
              {form.client_slugs.map(slug => {
                const client = clients.find(c => c.slug === slug)
                return (
                  <div key={slug} style={{ marginBottom: '10px' }}>
                    <div style={{ fontSize: '11px', fontWeight: '600', color: client?.color || t.gold, marginBottom: '5px', textTransform: 'uppercase', letterSpacing: '0.04em' }}>
                      {client?.name || slug}
                    </div>
                    <textarea
                      value={form.client_notes[slug] || ''}
                      onChange={e => setForm(f => ({ ...f, client_notes: { ...f.client_notes, [slug]: e.target.value } }))}
                      placeholder={`Notes for ${client?.name || slug} only...`}
                      rows={3}
                      style={{ ...inputStyle, resize: 'vertical', minHeight: '70px' }}
                    />
                  </div>
                )
              })}
            </Section>
          ) : (
            <Section label="Notes (optional)">
              <textarea
                value={form.notes}
                onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
                placeholder="What happened? Any context for next time..."
                rows={isMobile ? 3 : 4}
                style={{ ...inputStyle, resize: 'vertical', minHeight: '80px' }}
              />
            </Section>
          )}

          {/* Tasting details per brand */}
          {form.client_slugs.length > 0 && (
            <Section label="Tasting Details (optional)">
              {form.tastings.map(tasting => {
                const client = clients.find(c => c.slug === tasting.clientSlug)
                const prods = products[tasting.clientSlug] || []
                return (
                  <div key={tasting.clientSlug} style={{
                    backgroundColor: t.bg.input, border: `1px solid ${t.border.default}`,
                    borderRadius: '10px', padding: '12px', marginBottom: '10px',
                  }}>
                    <div style={{ fontSize: '12px', fontWeight: '600', color: client?.color || t.gold, marginBottom: '10px', textTransform: 'uppercase', letterSpacing: '0.04em' }}>
                      {client?.name}
                    </div>
                    {prods.length > 0 && (
                      <div style={{ marginBottom: '10px' }}>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px' }}>Products Tasted</div>
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                          {prods.map(p => {
                            const sel = tasting.products.includes(p.name)
                            return (
                              <button key={p.id} type="button" onClick={() => toggleTastingProduct(tasting.clientSlug, p.name)} style={{
                                padding: '4px 10px', borderRadius: '12px',
                                border: `1px solid ${sel ? client?.color || t.gold : t.border.default}`,
                                backgroundColor: sel ? ((client?.color || t.gold) + '20') : 'transparent',
                                color: sel ? (client?.color || t.gold) : t.text.muted,
                                fontSize: '12px', cursor: 'pointer',
                              }}>{p.name}</button>
                            )
                          })}
                        </div>
                      </div>
                    )}
                    <textarea
                      value={tasting.notes}
                      onChange={e => updateTasting(tasting.clientSlug, e.target.value)}
                      placeholder="Tasting notes, consumer reactions..."
                      rows={2}
                      style={{ ...inputStyle, fontSize: '13px', resize: 'none', marginTop: prods.length > 0 ? '8px' : 0 }}
                    />
                  </div>
                )
              })}
            </Section>
          )}

          {/* Placements */}
          {(form.status === 'New Placement' || form.status === 'Menu Feature Won') && !showPlacements && (
            <div style={{ marginBottom: '8px', padding: '8px 12px', borderRadius: '8px', backgroundColor: t.goldDim, border: `1px solid ${t.goldBorder}`, fontSize: '12px', color: t.gold, fontWeight: '600' }}>
              You selected "{form.status}" — don't forget to log the placement below
            </div>
          )}
          <div style={{ marginBottom: '18px' }}>
            <button
              type="button"
              onClick={() => {
                setShowPlacements(v => !v)
                if (!showPlacements && placements.length === 0) {
                  setPlacements([{ ...emptyPlacement(), client_slug: form.client_slugs[0] || '' }])
                }
              }}
              style={{
                display: 'flex', alignItems: 'center', gap: '8px', width: '100%',
                padding: '10px 14px', borderRadius: '8px', cursor: 'pointer',
                border: `1px solid ${showPlacements ? t.gold : t.border.default}`,
                backgroundColor: showPlacements ? t.goldDim : t.bg.input,
                color: showPlacements ? t.gold : t.text.secondary,
                fontSize: '13px', fontWeight: '500', textAlign: 'left',
                transition: 'all 150ms ease',
              }}
            >
              <Package size={14} />
              <span style={{ flex: 1 }}>Log Placement / Shelf Count</span>
              {placements.filter(p => p.product_name).length > 0 && (
                <span style={{ fontSize: '11px', backgroundColor: t.goldDim, color: t.gold, padding: '2px 7px', borderRadius: '10px', fontWeight: '600' }}>
                  {placements.filter(p => p.product_name).length}
                </span>
              )}
              {showPlacements ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            </button>

            {showPlacements && (
              <div style={{ marginTop: '10px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
                {placements.map((pl, i) => (
                  <div key={i} style={{ backgroundColor: t.bg.input, border: `1px solid ${t.border.default}`, borderRadius: '10px', padding: '14px', position: 'relative' }}>
                    {placements.length > 1 && (
                      <button type="button" onClick={() => setPlacements(ps => ps.filter((_, idx) => idx !== i))}
                        style={{ position: 'absolute', top: '10px', right: '10px', background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer', padding: '2px' }}>
                        <X size={14} />
                      </button>
                    )}

                    {/* Brand */}
                    {clients.length > 0 && (
                      <div style={{ marginBottom: '10px' }}>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Brand</div>
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                          {(form.client_slugs.length > 0 ? clients.filter(c => form.client_slugs.includes(c.slug)) : clients).map(c => (
                            <button key={c.slug} type="button" onClick={() => { setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, client_slug: c.slug, product_name: '' })); ensureProducts(c.slug) }}
                              style={{
                                padding: '5px 12px', borderRadius: '16px', fontSize: '12px', cursor: 'pointer',
                                border: `1px solid ${pl.client_slug === c.slug ? c.color : t.border.default}`,
                                backgroundColor: pl.client_slug === c.slug ? c.color + '20' : 'transparent',
                                color: pl.client_slug === c.slug ? c.color : t.text.muted,
                                fontWeight: pl.client_slug === c.slug ? '600' : '400',
                              }}>{c.name}</button>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Product */}
                    <div style={{ marginBottom: '10px' }}>
                      <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Product</div>
                      {pl.client_slug && (products[pl.client_slug] || []).length > 0 ? (
                        <select
                          value={pl.product_name}
                          onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, product_name: e.target.value }))}
                          style={{ ...inputStyle, fontSize: '13px' }}
                        >
                          <option value="">Select product...</option>
                          {(products[pl.client_slug] || []).map(p => <option key={p.id} value={p.name}>{p.name}</option>)}
                        </select>
                      ) : (
                        <input type="text" placeholder="Product name" value={pl.product_name}
                          onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, product_name: e.target.value }))}
                          style={{ ...inputStyle, fontSize: '13px' }} />
                      )}
                    </div>

                    {/* Type + Status */}
                    <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '8px', marginBottom: '10px' }}>
                      <div>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Type</div>
                        <select value={pl.placement_type}
                          onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, placement_type: e.target.value as PlacementType }))}
                          style={{ ...inputStyle, fontSize: '13px' }}>
                          <option value="shelf">Shelf</option>
                          <option value="menu">Menu</option>
                          <option value="cocktail">Cocktail</option>
                          <option value="well">Well</option>
                          <option value="retail">Retail</option>
                          <option value="seasonal">Seasonal</option>
                        </select>
                      </div>
                      <div>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Status</div>
                        <select value={pl.status}
                          onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, status: e.target.value as PlacementStatus }))}
                          style={{ ...inputStyle, fontSize: '13px' }}>
                          <option value="on_shelf">On Shelf</option>
                          <option value="committed">Committed</option>
                          <option value="ordered">Ordered</option>
                          <option value="reordering">Reordering</option>
                        </select>
                      </div>
                    </div>

                    {/* Shelf count + Price */}
                    <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '8px', marginBottom: '10px' }}>
                      <div>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Units on Shelf</div>
                        <input type="number" placeholder="e.g. 6" min="0" value={pl.shelf_count}
                          onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, shelf_count: e.target.value }))}
                          style={{ ...inputStyle, fontSize: '13px' }} />
                      </div>
                      <div>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Price Point ($)</div>
                        <input type="number" placeholder="e.g. 42" min="0" step="0.01" value={pl.price_point}
                          onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, price_point: e.target.value }))}
                          style={{ ...inputStyle, fontSize: '13px' }} />
                      </div>
                    </div>

                    {/* Notes */}
                    <div>
                      <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Notes (optional)</div>
                      <input type="text" placeholder="e.g. Front-of-bar, facing label out..." value={pl.notes}
                        onChange={e => setPlacements(ps => ps.map((p, idx) => idx !== i ? p : { ...p, notes: e.target.value }))}
                        style={{ ...inputStyle, fontSize: '13px' }} />
                    </div>
                  </div>
                ))}

                <button type="button"
                  onClick={() => setPlacements(ps => [...ps, { ...emptyPlacement(), client_slug: form.client_slugs[0] || '' }])}
                  style={{ fontSize: '12px', color: t.gold, background: 'none', border: `1px dashed ${t.border.default}`, borderRadius: '8px', padding: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px' }}>
                  <Plus size={13} /> Add another placement
                </button>
              </div>
            )}
          </div>

          {/* Follow-up */}
          <Section label="Follow-Up">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <div>
                <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '6px' }}>Schedule a follow-up in:</div>
                <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                  {[3, 7, 14, 30].map(days => (
                    <button key={days} type="button"
                      onClick={() => setForm(f => ({ ...f, followup_days: f.followup_days === days ? null : days, create_checkin: false }))}
                      style={{
                        padding: '7px 14px', borderRadius: '8px', fontSize: '12.5px', cursor: 'pointer',
                        border: `1px solid ${form.followup_days === days ? t.gold : t.border.default}`,
                        backgroundColor: form.followup_days === days ? t.goldDim : 'transparent',
                        color: form.followup_days === days ? t.gold : t.text.secondary,
                        fontWeight: form.followup_days === days ? '700' : '400',
                        transition: 'all 120ms ease',
                      }}>
                      {days}d
                    </button>
                  ))}
                </div>
              </div>
              <button type="button"
                onClick={() => setForm(f => ({ ...f, create_checkin: !f.create_checkin, followup_days: null }))}
                style={{
                  display: 'flex', alignItems: 'center', gap: '10px',
                  padding: '10px 14px', width: '100%', textAlign: 'left',
                  border: `1px solid ${form.create_checkin ? t.border.hover : t.border.subtle}`,
                  borderRadius: '8px',
                  backgroundColor: form.create_checkin ? t.bg.elevated : 'transparent',
                  color: form.create_checkin ? t.text.secondary : t.text.muted,
                  cursor: 'pointer', fontSize: '13px', transition: 'all 150ms ease',
                }}>
                <div style={{
                  width: 16, height: 16, borderRadius: '50%', flexShrink: 0,
                  border: `1.5px solid ${form.create_checkin ? t.text.muted : t.border.hover}`,
                  backgroundColor: form.create_checkin ? t.text.muted : 'transparent',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  {form.create_checkin && <Check size={9} color="#0f0f0d" strokeWidth={3} />}
                </div>
                <span>Remind me to check in</span>
                <span style={{ fontSize: '11px', color: t.text.muted, marginLeft: 'auto' }}>no set date</span>
              </button>
            </div>
          </Section>

          {error && (
            <div style={{
              display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 14px',
              backgroundColor: t.status.dangerBg, border: `1px solid rgba(224,82,82,0.2)`,
              borderRadius: '8px', color: t.status.danger, fontSize: '13px', marginBottom: '16px',
            }}>
              <AlertCircle size={15} />
              {error}
            </div>
          )}

          <button type="submit" disabled={saving || !form.account_id}
            style={{
              ...btnPrimary, width: '100%', justifyContent: 'center', padding: '13px', fontSize: '15px',
              opacity: saving || !form.account_id ? 0.6 : 1,
              cursor: saving || !form.account_id ? 'not-allowed' : 'pointer', marginTop: '8px',
            }}>
            {saving ? 'Saving...' : 'Log Visit'}
          </button>
        </form>
      )}
    </div>
  )

  const modalWrapper = isMobile ? (
    <div style={{ position: 'fixed', inset: 0, zIndex: 200 }}>
      <div onClick={onClose} style={{ position: 'absolute', inset: 0, backgroundColor: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)' }} />
      <div className="slide-up" style={{ ...mobileSheetContent, position: 'absolute', bottom: 0, left: 0, right: 0, maxHeight: '95vh', overflowY: 'auto' }}>
        {content}
      </div>
    </div>
  ) : (
    <div style={modalOverlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="fade-in" style={{
        backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`,
        borderRadius: '16px', width: '100%', maxWidth: '540px', maxHeight: '90vh', overflowY: 'auto',
      }}>
        {content}
      </div>
    </div>
  )

  return (
    <>
      {modalWrapper}
      {showAddAccountModal && (
        <AddAccountModal
          onClose={() => setShowAddAccountModal(false)}
          onAdded={acc => { selectAccount(acc as Account); setShowAddAccountModal(false) }}
          isMobile={isMobile}
        />
      )}
    </>
  )
}

function Section({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div style={{ marginBottom: '18px' }}>
      {label && <label style={labelStyle}>{label}</label>}
      {children}
    </div>
  )
}

'use client'
import { useState, useEffect, useCallback } from 'react'
import { DollarSign, TrendingUp, ChevronRight, Download, Receipt, Plus, X, Send, ExternalLink, AlertCircle, Check, Loader } from 'lucide-react'
import {
  BarChart, Bar, XAxis, YAxis, Tooltip,
  ResponsiveContainer, CartesianGrid,
} from 'recharts'
import Link from 'next/link'
import LayoutShell from '../layout-shell'
import StatCard from '../components/StatCard'
import { StatsSkeleton } from '../components/LoadingSkeleton'
import { getOrders, getClients, getCommissionTrend } from '../lib/data'
import { getSupabase } from '../lib/supabase'
import { t, card, badge, inputStyle, labelStyle, selectStyle } from '../lib/theme'
import { formatCurrency, formatShortDateMT, startOfMonthMT, resolveTotal } from '../lib/formatters'
import { clientLogoUrl } from '../lib/constants'
import type { Client, ClientInvoice } from '../lib/types'

const INVOICE_STATUS_COLORS: Record<string, string> = {
  draft: t.text.muted,
  sent: t.status.info,
  paid: t.status.success,
  void: t.text.muted,
  overdue: t.status.danger,
}

function ChartTooltip({ active, payload, label }: any) {
  if (!active || !payload?.length) return null
  return (
    <div style={{ backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`, borderRadius: '8px', padding: '10px 14px' }}>
      <div style={{ fontSize: '11px', color: t.text.muted, marginBottom: '4px' }}>{label}</div>
      {payload.map((p: any) => (
        <div key={p.dataKey} className="mono" style={{ fontSize: '13px', color: p.color, fontWeight: '600' }}>
          {p.name}: {formatCurrency(p.value)}
        </div>
      ))}
    </div>
  )
}

const DEFAULT_FORM = {
  client_slug: '', period_month: '', retainer_amount: '', commission_amount: '',
  due_date: '', admin_notes: '',
}

export default function FinancePage() {
  const [clients, setClients] = useState<Client[]>([])
  const [orders, setOrders] = useState<any[]>([])
  const [trendData, setTrendData] = useState<any[]>([])
  const [invoices, setInvoices] = useState<ClientInvoice[]>([])
  const [depletions, setDepletions] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [invoicesLoading, setInvoicesLoading] = useState(true)
  const [isMobile, setIsMobile] = useState(false)
  const [showCreate, setShowCreate] = useState(false)
  const [form, setForm] = useState(DEFAULT_FORM)
  const [saving, setSaving] = useState(false)
  const [sendingId, setSendingId] = useState<string | null>(null)
  const [voidingId, setVoidingId] = useState<string | null>(null)
  const [err, setErr] = useState('')
  const [toast, setToast] = useState('')

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  useEffect(() => {
    const twelveMonthsAgo = new Date(); twelveMonthsAgo.setMonth(twelveMonthsAgo.getMonth() - 12)
    Promise.all([getClients(), getOrders(), getCommissionTrend(twelveMonthsAgo)])
      .then(([cls, ords, trend]) => {
        setClients(cls)
        setOrders(ords.filter((o: any) => o.status === 'sent' || o.status === 'fulfilled'))
        const months: Record<string, { month: string; commission: number; revenue: number }> = {}
        for (let i = 11; i >= 0; i--) {
          const d = new Date(); d.setMonth(d.getMonth() - i)
          const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`
          months[key] = { month: d.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }), commission: 0, revenue: 0 }
        }
        const rateMapTrend = Object.fromEntries(cls.map((c: any) => [c.slug, c.commission_rate || 0]))
        trend.forEach((o: any) => {
          const key = (o.sent_at || o.created_at).slice(0, 7)
          if (months[key]) {
            const stored = Number(o.commission_amount) || 0
            const rev = Number(o.total_amount) || resolveTotal(o)
            months[key].commission += stored > 0 ? stored : rev * (rateMapTrend[o.client_slug] || 0)
            months[key].revenue += rev
          }
        })
        setTrendData(Object.values(months))
        setLoading(false)
      })
      .catch(() => setLoading(false))
  }, [])

  const loadInvoices = useCallback(async () => {
    setInvoicesLoading(true)
    try {
      const { data: { session } } = await getSupabase().auth.getSession()
      const token = session?.access_token
      const [invRes, depRes] = await Promise.all([
        fetch('/api/billing/invoices', { headers: { Authorization: `Bearer ${token}` } }),
        fetch('/api/billing/depletions', { headers: { Authorization: `Bearer ${token}` } }),
      ])
      if (invRes.ok) setInvoices(await invRes.json())
      if (depRes.ok) setDepletions(await depRes.json())
    } catch { /* non-fatal */ }
    finally { setInvoicesLoading(false) }
  }, [])

  useEffect(() => { loadInvoices() }, [loadInvoices])

  function showToast(msg: string) {
    setToast(msg)
    setTimeout(() => setToast(''), 3000)
  }

  async function getToken() {
    const { data: { session } } = await getSupabase().auth.getSession()
    return session?.access_token
  }

  // Auto-fill retainer when client changes
  function handleClientChange(slug: string) {
    const client = clients.find(c => c.slug === slug)
    setForm(f => ({
      ...f,
      client_slug: slug,
      retainer_amount: client?.monthly_retainer_fee ? String(client.monthly_retainer_fee) : f.retainer_amount,
    }))
  }

  // Auto-fill commission from pending depletions for selected client + prior month
  useEffect(() => {
    if (!form.client_slug || !form.period_month) return
    // Commission from depletions comes from the PREVIOUS month's depletions
    const [y, m] = form.period_month.split('-').map(Number)
    const prevDate = new Date(y, m - 2, 1)
    const prevMonth = `${prevDate.getFullYear()}-${String(prevDate.getMonth() + 1).padStart(2, '0')}`
    const client = clients.find(c => c.slug === form.client_slug)
    const rate = client?.commission_rate || 0
    const pending = depletions.filter(d => d.client_slug === form.client_slug && d.period_month === prevMonth && !d.invoice_id)
    const commissionTotal = pending.reduce((s: number, d: any) => s + (Number(d.sale_value) || 0), 0) * rate
    if (commissionTotal > 0) {
      setForm(f => ({ ...f, commission_amount: commissionTotal.toFixed(2) }))
    }
  }, [form.client_slug, form.period_month, depletions, clients])

  async function handleCreateInvoice() {
    if (!form.client_slug || !form.period_month) return
    setSaving(true); setErr('')
    try {
      const token = await getToken()
      const res = await fetch('/api/billing/invoices', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({
          client_slug: form.client_slug,
          period_month: form.period_month,
          retainer_amount: Number(form.retainer_amount) || 0,
          commission_amount: Number(form.commission_amount) || 0,
          due_date: form.due_date || null,
          admin_notes: form.admin_notes || null,
          line_items: [
            ...(Number(form.retainer_amount) > 0 ? [{ description: `Monthly retainer — ${form.period_month}`, amount: Number(form.retainer_amount), type: 'retainer' }] : []),
            ...(Number(form.commission_amount) > 0 ? [{ description: `Commission earned — prev. month depletions`, amount: Number(form.commission_amount), type: 'commission' }] : []),
          ],
        }),
      })
      let json: any = {}
      try { json = await res.json() } catch { /* response wasn't JSON */ }
      if (!res.ok) { setErr(json.error || `Server error (${res.status})`); return }
      setShowCreate(false)
      setForm(DEFAULT_FORM)
      await loadInvoices()
      showToast('Invoice created')
    } catch (e: any) { setErr(e?.message || 'Network error') }
    finally { setSaving(false) }
  }

  async function handleSendInvoice(id: string) {
    setSendingId(id); setErr('')
    try {
      const token = await getToken()
      const res = await fetch(`/api/billing/invoices/${id}/send`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      })
      let json: any = {}
      try { json = await res.json() } catch { /* response wasn't JSON */ }
      if (!res.ok) { setErr(json.error || `Server error (${res.status})`); setSendingId(null); return }
      await loadInvoices()
      showToast('Invoice sent via Stripe')
    } catch (e: any) { setErr(e?.message || 'Network error') }
    finally { setSendingId(null) }
  }

  async function handleVoidInvoice(id: string) {
    if (!confirm('Void this invoice? This cannot be undone.')) return
    setVoidingId(id)
    try {
      const token = await getToken()
      await fetch(`/api/billing/invoices/${id}`, { method: 'DELETE', headers: { Authorization: `Bearer ${token}` } })
      await loadInvoices()
      showToast('Invoice voided')
    } catch { /* non-fatal */ }
    finally { setVoidingId(null) }
  }

  const rateMap = Object.fromEntries(clients.map(c => [c.slug, c.commission_rate || 0]))
  function resolveCommission(o: any): number {
    const stored = Number(o.commission_amount) || 0
    if (stored > 0) return stored
    return resolveTotal(o) * (rateMap[o.client_slug] || 0)
  }

  const monthStart = startOfMonthMT()
  const effectiveDate = (o: any) => o.sent_at || o.created_at
  const monthOrders = orders.filter(o => effectiveDate(o) >= monthStart)
  const thisMonthCommission = monthOrders.reduce((s, o) => s + resolveCommission(o), 0)
  const thisMonthRevenue = monthOrders.reduce((s, o) => s + resolveTotal(o), 0)
  const mtYear = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Denver' }).slice(0, 4)
  const ytdStart = `${mtYear}-01-01`
  const ytdOrders = orders.filter(o => effectiveDate(o) >= ytdStart)
  const ytdCommission = ytdOrders.reduce((s, o) => s + resolveCommission(o), 0)
  const ytdRevenue = ytdOrders.reduce((s, o) => s + resolveTotal(o), 0)
  const retainerMRR = clients.reduce((s, c) => s + (c.monthly_retainer_fee || 0), 0)

  const perClient = clients.map(c => {
    const clientOrders = monthOrders.filter(o => o.client_slug === c.slug)
    const commission = clientOrders.reduce((s: number, o: any) => s + resolveCommission(o), 0)
    const revenue = clientOrders.reduce((s: number, o: any) => s + resolveTotal(o), 0)
    const ytdComm = ytdOrders.filter((o: any) => o.client_slug === c.slug).reduce((s: number, o: any) => s + resolveCommission(o), 0)
    const ytdRev = ytdOrders.filter((o: any) => o.client_slug === c.slug).reduce((s: number, o: any) => s + resolveTotal(o), 0)
    return { ...c, commission, revenue, ytdCommission: ytdComm, ytdRevenue: ytdRev, orderCount: clientOrders.length }
  })

  const recentOrders = [...orders].sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()).slice(0, 20)

  const draftInvoices = invoices.filter(i => i.status === 'draft')
  const activeInvoices = invoices.filter(i => i.status !== 'void')
  const overdueInvoices = invoices.filter(i => i.status === 'overdue')

  const currentMonth = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Denver' }).slice(0, 7)

  function exportCSV() {
    const rows = [
      ['PO Number', 'Date', 'Client', 'Deliver To', 'Revenue', 'Commission', 'Status'],
      ...orders.map(o => [
        o.po_number || '',
        (o.created_at || '').slice(0, 10),
        clients.find(c => c.slug === o.client_slug)?.name || o.client_slug || '',
        o.deliver_to_name || '',
        resolveTotal(o).toFixed(2),
        resolveCommission(o).toFixed(2),
        o.status || '',
      ]),
    ]
    const csv = rows.map(r => r.map(v => `"${String(v).replace(/"/g, '""')}"`).join(',')).join('\n')
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a'); a.href = url
    a.download = `orders-${new Date().toISOString().slice(0, 10)}.csv`
    a.click(); URL.revokeObjectURL(url)
  }

  return (
    <LayoutShell>
      <div style={{ padding: isMobile ? '16px' : '32px 48px', maxWidth: '1200px', margin: '0 auto', width: '100%' }}>

        {/* Toast */}
        {toast && (
          <div style={{ position: 'fixed', bottom: '24px', left: '50%', transform: 'translateX(-50%)', backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`, borderRadius: '10px', padding: '10px 18px', fontSize: '13px', color: t.text.primary, zIndex: 9999, display: 'flex', alignItems: 'center', gap: '8px', boxShadow: '0 8px 32px rgba(0,0,0,0.4)' }}>
            <Check size={14} color={t.status.success} /> {toast}
          </div>
        )}

        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: '28px', gap: '12px' }}>
          <div>
            <h1 className="page-h1" style={{ fontSize: isMobile ? '18px' : '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em' }}>Finance</h1>
            <p style={{ fontSize: '13px', color: t.text.muted, marginTop: '2px' }}>Commission, revenue, and client billing</p>
          </div>
          <button onClick={exportCSV} style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 14px', borderRadius: '8px', fontSize: '13px', border: `1px solid ${t.border.default}`, backgroundColor: 'transparent', color: t.text.secondary, cursor: 'pointer', flexShrink: 0 }}>
            <Download size={14} /> Export CSV
          </button>
        </div>

        {/* Stats */}
        {loading ? <StatsSkeleton /> : (
          <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr 1fr' : 'repeat(5, 1fr)', gap: '12px', marginBottom: '28px' }}>
            <StatCard label="Commission This Month" value={formatCurrency(thisMonthCommission)} icon={<DollarSign size={20} />} color={t.gold} />
            <StatCard label="Revenue This Month" value={formatCurrency(thisMonthRevenue)} icon={<TrendingUp size={20} />} color={t.status.success} />
            <StatCard label="Commission YTD" value={formatCurrency(ytdCommission)} icon={<DollarSign size={20} />} color={t.status.info} />
            <StatCard label="Revenue YTD" value={formatCurrency(ytdRevenue)} icon={<TrendingUp size={20} />} color={t.text.secondary} />
            <StatCard label="Retainer MRR" value={formatCurrency(retainerMRR)} icon={<Receipt size={20} />} color={t.status.warning} />
          </div>
        )}

        {/* Overdue alert */}
        {overdueInvoices.length > 0 && (
          <div style={{ ...card, padding: '14px 18px', marginBottom: '20px', border: `1px solid ${t.status.danger}44`, backgroundColor: t.status.danger + '10', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <AlertCircle size={16} color={t.status.danger} />
            <span style={{ fontSize: '13px', color: t.status.danger, fontWeight: '600' }}>
              {overdueInvoices.length} invoice{overdueInvoices.length > 1 ? 's are' : ' is'} overdue — {overdueInvoices.map(i => clients.find(c => c.slug === i.client_slug)?.name || i.client_slug).join(', ')}
            </span>
          </div>
        )}

        {/* Chart */}
        <div style={{ ...card, marginBottom: '20px', padding: isMobile ? '16px' : '22px 24px' }}>
          <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '18px' }}>
            Commission — Last 12 Months
          </div>
          <ResponsiveContainer width="100%" height={isMobile ? 160 : 200}>
            <BarChart data={trendData} barCategoryGap="30%">
              <CartesianGrid strokeDasharray="3 3" stroke={t.border.subtle} vertical={false} />
              <XAxis dataKey="month" tick={{ fill: t.text.muted, fontSize: isMobile ? 9 : 11 }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fill: t.text.muted, fontSize: isMobile ? 9 : 11 }} axisLine={false} tickLine={false} tickFormatter={v => `$${v}`} />
              <Tooltip content={<ChartTooltip />} cursor={{ fill: 'rgba(255,255,255,0.04)' }} />
              <Bar dataKey="commission" name="Commission" fill={t.gold} radius={[3, 3, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Billing / Invoices */}
        <div style={{ ...card, marginBottom: '20px', padding: isMobile ? '16px' : '22px 24px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
            <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
              Client Invoices
              {draftInvoices.length > 0 && <span style={{ marginLeft: '8px', fontSize: '10px', backgroundColor: t.status.warning + '30', color: t.status.warning, borderRadius: '6px', padding: '2px 6px', fontWeight: '700' }}>{draftInvoices.length} need review</span>}
            </div>
            <button onClick={() => { setForm({ ...DEFAULT_FORM, period_month: currentMonth }); setErr(''); setShowCreate(true) }} style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '6px 12px', borderRadius: '8px', fontSize: '12px', fontWeight: '600', backgroundColor: t.gold, color: '#0c0c0a', border: 'none', cursor: 'pointer' }}>
              <Plus size={13} /> New Invoice
            </button>
          </div>

          {err && <div style={{ fontSize: '12px', color: t.status.danger, marginBottom: '12px', padding: '8px 12px', backgroundColor: t.status.danger + '15', borderRadius: '8px' }}>{err}</div>}

          {invoicesLoading ? (
            <div style={{ fontSize: '13px', color: t.text.muted, padding: '12px 0' }}>Loading invoices…</div>
          ) : activeInvoices.length === 0 ? (
            <div style={{ fontSize: '13px', color: t.text.muted, padding: '12px 0' }}>No invoices yet. Create one to start billing clients.</div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
              {activeInvoices.map((inv) => {
                const cl = clients.find(c => c.slug === inv.client_slug)
                const total = (inv.retainer_amount || 0) + (inv.commission_amount || 0)
                const isSending = sendingId === inv.id
                const isVoiding = voidingId === inv.id
                return (
                  <div key={inv.id} style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px 0', borderBottom: `1px solid ${t.border.subtle}`, flexWrap: isMobile ? 'wrap' : 'nowrap' }}>
                    <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: INVOICE_STATUS_COLORS[inv.status] || t.text.muted, flexShrink: 0 }} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: t.text.primary }}>
                        {cl?.name || inv.client_slug}
                        <span style={{ marginLeft: '8px', fontSize: '11px', fontWeight: '400', color: t.text.muted }}>{inv.period_month}</span>
                      </div>
                      <div style={{ fontSize: '11px', color: t.text.muted, marginTop: '2px' }}>
                        {inv.retainer_amount > 0 && `Retainer ${formatCurrency(inv.retainer_amount)}`}
                        {inv.retainer_amount > 0 && inv.commission_amount > 0 && ' + '}
                        {inv.commission_amount > 0 && `Commission ${formatCurrency(inv.commission_amount)}`}
                        {inv.due_date && ` · Due ${formatShortDateMT(inv.due_date)}`}
                      </div>
                    </div>
                    <div className="mono" style={{ fontSize: '14px', fontWeight: '700', color: t.text.primary, flexShrink: 0 }}>{formatCurrency(total)}</div>
                    <span style={{ fontSize: '10px', fontWeight: '700', textTransform: 'uppercase', padding: '2px 7px', borderRadius: '6px', backgroundColor: INVOICE_STATUS_COLORS[inv.status] + '20', color: INVOICE_STATUS_COLORS[inv.status], flexShrink: 0 }}>{inv.status}</span>
                    <div style={{ display: 'flex', gap: '6px', flexShrink: 0 }}>
                      {inv.status === 'draft' && (
                        <button onClick={() => handleSendInvoice(inv.id)} disabled={isSending} style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '5px 10px', borderRadius: '7px', fontSize: '11px', fontWeight: '600', backgroundColor: t.status.info + '20', color: t.status.info, border: `1px solid ${t.status.info}44`, cursor: 'pointer', opacity: isSending ? 0.6 : 1 }}>
                          {isSending ? <Loader size={11} /> : <Send size={11} />} Send
                        </button>
                      )}
                      {inv.stripe_invoice_url && (
                        <a href={inv.stripe_invoice_url} target="_blank" rel="noopener noreferrer" style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '5px 10px', borderRadius: '7px', fontSize: '11px', fontWeight: '600', backgroundColor: t.bg.card, color: t.text.secondary, border: `1px solid ${t.border.default}`, cursor: 'pointer', textDecoration: 'none' }}>
                          <ExternalLink size={11} /> View
                        </a>
                      )}
                      {(inv.status === 'draft' || inv.status === 'sent') && (
                        <button onClick={() => handleVoidInvoice(inv.id)} disabled={isVoiding} style={{ padding: '5px 8px', borderRadius: '7px', fontSize: '11px', fontWeight: '600', backgroundColor: 'transparent', color: t.text.muted, border: `1px solid ${t.border.default}`, cursor: 'pointer', opacity: isVoiding ? 0.6 : 1 }}>
                          {isVoiding ? <Loader size={11} /> : <X size={11} />}
                        </button>
                      )}
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : (perClient.length > 0 ? '1fr 1fr' : '1fr'), gap: '20px' }}>

          {/* Per-client breakdown */}
          {perClient.length > 0 && (
            <div style={card}>
              <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '16px' }}>
                This Month by Brand
              </div>
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                {perClient.map((c, i) => (
                  <div key={c.slug} style={{ display: 'flex', alignItems: 'center', gap: isMobile ? '8px' : '14px', padding: '14px 0', borderBottom: i < perClient.length - 1 ? `1px solid ${t.border.subtle}` : 'none', flexWrap: isMobile ? 'wrap' : 'nowrap' }}>
                    {(() => {
                      const logo = clientLogoUrl(c)
                      return logo ? (
                        <img src={logo} alt={c.name} style={{ width: '32px', height: '32px', objectFit: 'contain', flexShrink: 0, borderRadius: '6px', backgroundColor: 'rgba(255,255,255,0.04)' }} />
                      ) : (
                        <div style={{ width: '32px', height: '32px', borderRadius: '6px', backgroundColor: `${c.color}22`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                          <span style={{ fontSize: '13px', fontWeight: '700', color: c.color }}>{c.name[0]}</span>
                        </div>
                      )
                    })()}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: t.text.primary }}>{c.name}</div>
                      <div style={{ fontSize: '11px', color: t.text.muted, marginTop: '2px' }}>
                        {c.orderCount} order{c.orderCount !== 1 ? 's' : ''} · {(c.commission_rate * 100).toFixed(0)}% rate
                        {(c.monthly_retainer_fee ?? 0) > 0 && ` · ${formatCurrency(c.monthly_retainer_fee!)} retainer`}
                      </div>
                    </div>
                    <div style={{ textAlign: 'right', flexShrink: 0 }}>
                      <div className="mono" style={{ fontSize: '14px', fontWeight: '700', color: t.text.primary }}>{formatCurrency(c.commission)}</div>
                      <div style={{ fontSize: '11px', color: t.text.muted }}>of {formatCurrency(c.revenue)}</div>
                    </div>
                    <div style={{ width: 60, height: 4, backgroundColor: t.border.default, borderRadius: 2, flexShrink: 0 }}>
                      <div style={{ width: `${ytdCommission > 0 ? Math.min(100, (c.ytdCommission / ytdCommission) * 100) : 0}%`, height: '100%', backgroundColor: c.color, borderRadius: 2 }} />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Recent orders */}
          <div style={{ ...card, overflowX: isMobile ? 'auto' : 'visible' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
              <div style={{ fontSize: '11px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em' }}>Recent Orders</div>
              <Link href="/orders" style={{ fontSize: '12px', color: t.text.muted, textDecoration: 'none', display: 'flex', alignItems: 'center', gap: '2px' }}>
                All <ChevronRight size={12} />
              </Link>
            </div>
            {recentOrders.length === 0 ? (
              <div style={{ fontSize: '13px', color: t.text.muted }}>No orders yet</div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                {recentOrders.map((o, i) => {
                  const client = clients.find(c => c.slug === o.client_slug)
                  const total = resolveTotal(o)
                  return (
                    <div key={o.id} style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px 0', borderBottom: i < recentOrders.length - 1 ? `1px solid ${t.border.subtle}` : 'none' }}>
                      <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: client?.color || t.gold, flexShrink: 0 }} />
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div className="mono" style={{ fontSize: '12px', fontWeight: '600', color: t.text.primary }}>{o.po_number}</div>
                        <div style={{ fontSize: '11px', color: t.text.muted, marginTop: '1px' }}>{o.deliver_to_name} · {formatShortDateMT(o.created_at)}</div>
                      </div>
                      <div style={{ textAlign: 'right', flexShrink: 0 }}>
                        <div className="mono" style={{ fontSize: '13px', fontWeight: '600', color: t.text.primary }}>{formatCurrency(total)}</div>
                        <span style={badge.orderStatus(o.status)}>{o.status}</span>
                      </div>
                    </div>
                  )
                })}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Create Invoice Modal */}
      {showCreate && (
        <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '20px' }}>
          <div style={{ backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`, borderRadius: '16px', padding: '28px', width: '100%', maxWidth: '480px', maxHeight: '90vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
              <h3 style={{ fontSize: '17px', fontWeight: '600', color: t.text.primary }}>New Invoice</h3>
              <button onClick={() => setShowCreate(false)} style={{ background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer' }}><X size={18} /></button>
            </div>

            {err && <div style={{ fontSize: '12px', color: t.status.danger, marginBottom: '12px', padding: '8px 12px', backgroundColor: t.status.danger + '15', borderRadius: '8px' }}>{err}</div>}

            <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
              <div>
                <label style={labelStyle}>Client</label>
                <select value={form.client_slug} onChange={e => handleClientChange(e.target.value)} style={selectStyle}>
                  <option value="">Select client…</option>
                  {clients.map(c => <option key={c.slug} value={c.slug}>{c.name}</option>)}
                </select>
              </div>

              <div>
                <label style={labelStyle}>Billing Month</label>
                <input type="month" value={form.period_month} onChange={e => setForm(f => ({ ...f, period_month: e.target.value }))} style={inputStyle} />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                <div>
                  <label style={labelStyle}>Retainer ($)</label>
                  <input type="number" min="0" step="0.01" value={form.retainer_amount} onChange={e => setForm(f => ({ ...f, retainer_amount: e.target.value }))} placeholder="0.00" style={inputStyle} />
                </div>
                <div>
                  <label style={labelStyle}>Commission ($)</label>
                  <input type="number" min="0" step="0.01" value={form.commission_amount} onChange={e => setForm(f => ({ ...f, commission_amount: e.target.value }))} placeholder="Auto-fills from depletions" style={inputStyle} />
                </div>
              </div>

              {form.commission_amount && Number(form.commission_amount) > 0 && (
                <div style={{ fontSize: '11px', color: t.status.info, backgroundColor: t.status.info + '15', borderRadius: '8px', padding: '8px 12px' }}>
                  Commission auto-calculated from prior month depletions. Edit the amount above if needed.
                </div>
              )}

              <div>
                <label style={labelStyle}>Due Date</label>
                <input type="date" value={form.due_date} onChange={e => setForm(f => ({ ...f, due_date: e.target.value }))} style={inputStyle} />
              </div>

              <div>
                <label style={labelStyle}>Admin Notes (optional)</label>
                <textarea value={form.admin_notes} onChange={e => setForm(f => ({ ...f, admin_notes: e.target.value }))} rows={2} placeholder="Visible on the Stripe invoice…" style={{ ...inputStyle, resize: 'none' }} />
              </div>

              <div style={{ borderTop: `1px solid ${t.border.subtle}`, paddingTop: '12px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '14px', fontWeight: '700', color: t.text.primary }}>
                  <span>Total</span>
                  <span className="mono">{formatCurrency((Number(form.retainer_amount) || 0) + (Number(form.commission_amount) || 0))}</span>
                </div>
                <div style={{ fontSize: '11px', color: t.text.muted, marginTop: '4px' }}>Invoice will be saved as a draft for your review before sending.</div>
              </div>
            </div>

            <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '20px' }}>
              <button onClick={() => setShowCreate(false)} style={{ padding: '8px 16px', borderRadius: '8px', fontSize: '13px', backgroundColor: 'transparent', color: t.text.secondary, border: `1px solid ${t.border.default}`, cursor: 'pointer' }}>Cancel</button>
              <button onClick={handleCreateInvoice} disabled={saving || !form.client_slug || !form.period_month} style={{ padding: '8px 16px', borderRadius: '8px', fontSize: '13px', fontWeight: '600', backgroundColor: t.gold, color: '#0c0c0a', border: 'none', cursor: 'pointer', opacity: saving || !form.client_slug || !form.period_month ? 0.6 : 1 }}>
                {saving ? 'Saving…' : 'Save Draft'}
              </button>
            </div>
          </div>
        </div>
      )}
    </LayoutShell>
  )
}

'use client'
import { useState, useEffect } from 'react'
import { Users, ClipboardList, Plus, X, Check } from 'lucide-react'
import LayoutShell from '../layout-shell'
import { getTasks, createTask } from '../lib/data'
import { getSupabase } from '../lib/supabase'
import { t, card, btnPrimary, btnSecondary, inputStyle, labelStyle, selectStyle } from '../lib/theme'
import { formatShortDateMT } from '../lib/formatters'

export default function InternHubPage() {
  const [interns, setInterns] = useState<any[]>([])
  const [tasks, setTasks] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [showAssign, setShowAssign] = useState(false)
  const [form, setForm] = useState({ title: '', description: '', assigned_to: '', due_date: '', priority: 'medium' })
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  useEffect(() => {
    const sb = getSupabase()
    Promise.all([
      sb.from('user_profiles').select('*').eq('role', 'intern'),
      getTasks(),
    ]).then(([{ data: internData }, taskData]) => {
      setInterns(internData || [])
      setTasks(taskData.filter(t => t.assigned_to && internData?.find((i: any) => i.id === t.assigned_to)))
      setLoading(false)
    }).catch(() => setLoading(false))
  }, [])

  async function handleAssign() {
    if (!form.title || !form.assigned_to) return
    await createTask({
      title: form.title,
      description: form.description || undefined,
      assigned_to: form.assigned_to,
      due_date: form.due_date || undefined,
      priority: form.priority as any,
    })
    const sb = getSupabase()
    const allTasks = await getTasks()
    const { data: internData } = await sb.from('user_profiles').select('*').eq('role', 'intern')
    setTasks(allTasks.filter(t => t.assigned_to && internData?.find((i: any) => i.id === t.assigned_to)))
    setShowAssign(false)
    setForm({ title: '', description: '', assigned_to: '', due_date: '', priority: 'medium' })
  }

  async function completeTask(id: string) {
    const sb = getSupabase()
    await sb.from('tasks').update({ completed: true, completed_at: new Date().toISOString() }).eq('id', id)
    setTasks(prev => prev.filter(t => t.id !== id))
  }

  return (
    <LayoutShell>
      <div style={{ padding: isMobile ? '16px' : '32px 48px', maxWidth: '1100px', margin: '0 auto', width: '100%' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h1 style={{ fontSize: '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em' }}>Intern Hub</h1>
            <p style={{ fontSize: '13px', color: t.text.muted, marginTop: '2px' }}>Manage intern assignments and tasks</p>
          </div>
          <button onClick={() => setShowAssign(true)} style={btnPrimary}><Plus size={16} /> Assign Task</button>
        </div>

        {/* Intern cards */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '14px', marginBottom: '28px' }}>
          {interns.map(intern => {
            const internTasks = tasks.filter(t => t.assigned_to === intern.id)
            const open = internTasks.filter(t => !t.completed).length
            return (
              <div key={intern.id} style={{ ...card, padding: '18px 20px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px' }}>
                  <div style={{ width: 36, height: 36, borderRadius: '10px', backgroundColor: t.gold + '20', border: `1px solid ${t.gold}40`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '14px', fontWeight: '700', color: t.gold }}>
                    {intern.name?.charAt(0) || '?'}
                  </div>
                  <div>
                    <div style={{ fontSize: '14px', fontWeight: '600', color: t.text.primary }}>{intern.name}</div>
                    <div style={{ fontSize: '11px', color: t.text.muted }}>{intern.full_name || intern.email || 'Intern'}</div>
                  </div>
                </div>
                <div style={{ fontSize: '12px', color: t.text.secondary }}>
                  <span style={{ fontWeight: '600', color: open > 0 ? t.gold : t.text.muted }}>{open}</span> open task{open !== 1 ? 's' : ''}
                </div>
              </div>
            )
          })}
          {interns.length === 0 && !loading && (
            <div style={{ gridColumn: '1 / -1', textAlign: 'center', padding: '40px 0', color: t.text.muted, fontSize: '14px' }}>
              No interns found. Invite them from Supabase auth with role = intern.
            </div>
          )}
        </div>

        {/* Task list */}
        <h2 style={{ fontSize: '15px', fontWeight: '700', color: t.text.primary, marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <ClipboardList size={16} /> Open Intern Tasks
        </h2>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {tasks.filter(t => !t.completed).length === 0 ? (
            <div style={{ color: t.text.muted, fontSize: '13px', padding: '20px 0' }}>No open tasks assigned to interns</div>
          ) : tasks.filter(tk => !tk.completed).map(task => {
            const intern = interns.find(i => i.id === task.assigned_to)
            return (
              <div key={task.id} style={{ ...card, padding: '14px 18px', display: 'flex', alignItems: 'center', gap: '12px' }}>
                <button onClick={() => completeTask(task.id)} style={{ width: 22, height: 22, borderRadius: '6px', border: `1.5px solid ${t.border.hover}`, background: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                  <Check size={12} color={t.text.muted} />
                </button>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: '14px', fontWeight: '500', color: t.text.primary }}>{task.title}</div>
                  {task.description && <div style={{ fontSize: '12px', color: t.text.muted, marginTop: '2px' }}>{task.description}</div>}
                </div>
                <div style={{ display: 'flex', gap: '10px', alignItems: 'center', flexShrink: 0 }}>
                  {intern && <span style={{ fontSize: '11px', color: t.text.secondary }}>{intern.name}</span>}
                  {task.due_date && <span style={{ fontSize: '11px', color: t.text.muted }}>{formatShortDateMT(task.due_date)}</span>}
                  {task.priority && <span style={{ fontSize: '10px', padding: '2px 6px', borderRadius: '6px', backgroundColor: task.priority === 'high' ? '#e0525220' : t.bg.elevated, color: task.priority === 'high' ? '#e05252' : t.text.muted, fontWeight: '600', textTransform: 'uppercase' }}>{task.priority}</span>}
                </div>
              </div>
            )
          })}
        </div>

        {/* Assign Task Modal */}
        {showAssign && (
          <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '20px' }}>
            <div style={{ backgroundColor: t.bg.elevated, border: `1px solid ${t.border.hover}`, borderRadius: '16px', padding: '28px', width: '100%', maxWidth: '440px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                <h3 style={{ fontSize: '17px', fontWeight: '600', color: t.text.primary }}>Assign Task</h3>
                <button onClick={() => setShowAssign(false)} style={{ background: 'none', border: 'none', color: t.text.muted, cursor: 'pointer' }}><X size={18} /></button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div><label style={labelStyle}>Task Title</label><input type="text" value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} placeholder="What needs to be done?" style={inputStyle} /></div>
                <div><label style={labelStyle}>Assign To</label>
                  <select value={form.assigned_to} onChange={e => setForm(f => ({ ...f, assigned_to: e.target.value }))} style={selectStyle}>
                    <option value="">Select intern...</option>
                    {interns.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                  </select>
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '10px' }}>
                  <div><label style={labelStyle}>Due Date</label><input type="date" value={form.due_date} onChange={e => setForm(f => ({ ...f, due_date: e.target.value }))} style={inputStyle} /></div>
                  <div><label style={labelStyle}>Priority</label>
                    <select value={form.priority} onChange={e => setForm(f => ({ ...f, priority: e.target.value }))} style={selectStyle}>
                      <option value="low">Low</option>
                      <option value="medium">Medium</option>
                      <option value="high">High</option>
                    </select>
                  </div>
                </div>
                <div><label style={labelStyle}>Description</label><textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} rows={2} style={{ ...inputStyle, resize: 'none' }} /></div>
              </div>
              <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '20px' }}>
                <button onClick={() => setShowAssign(false)} style={btnSecondary}>Cancel</button>
                <button onClick={handleAssign} disabled={!form.title || !form.assigned_to} style={{ ...btnPrimary, opacity: (!form.title || !form.assigned_to) ? 0.6 : 1 }}>Assign</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </LayoutShell>
  )
}

'use client'
import { useState, useEffect, useRef } from 'react'
import { Upload, AlertCircle, CheckCircle, X } from 'lucide-react'
import LayoutShell from '../../layout-shell'
import { getSupabase } from '../../lib/supabase'
import { t, card, btnPrimary, inputStyle, labelStyle, selectStyle } from '../../lib/theme'
import { formatShortDateMT } from '../../lib/formatters'

type AssetType = 'Social Media Graphic' | 'Video' | 'Copy/Caption' | 'Blog Post' | 'Email Draft' | 'Photo' | 'Other'
type AssetStatus = 'pending' | 'approved' | 'changes_requested'

interface InternAsset {
  id: string
  title: string
  asset_type: AssetType
  project_id?: string
  file_url?: string
  notes?: string
  status: AssetStatus
  feedback?: string
  submitted_by?: string
  created_at: string
}

interface InternProject {
  id: string
  title: string
}

const ASSET_TYPES: AssetType[] = [
  'Social Media Graphic', 'Video', 'Copy/Caption',
  'Blog Post', 'Email Draft', 'Photo', 'Other',
]

const STATUS_STYLE: Record<AssetStatus, { label: string; color: string; bg: string }> = {
  pending:           { label: 'Pending Review', color: t.status.warning, bg: t.status.warningBg },
  approved:          { label: 'Approved',        color: t.status.success, bg: t.status.successBg },
  changes_requested: { label: 'Changes Needed',  color: t.status.danger,  bg: t.status.dangerBg  },
}

export default function InternAssetsPage() {
  const [userId, setUserId] = useState<string | null>(null)
  const [assets, setAssets] = useState<InternAsset[]>([])
  const [projects, setProjects] = useState<InternProject[]>([])
  const [loading, setLoading] = useState(true)
  const [uploading, setUploading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState(false)
  const [isMobile, setIsMobile] = useState(false)
  const fileRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  const [form, setForm] = useState({
    title: '',
    asset_type: 'Social Media Graphic' as AssetType,
    project_id: '',
    notes: '',
  })
  const [file, setFile] = useState<File | null>(null)

  async function loadAssets(uid: string) {
    const sb = getSupabase()
    const { data } = await sb
      .from('intern_assets')
      .select('*')
      .eq('submitted_by', uid)
      .order('created_at', { ascending: false })
    setAssets((data || []) as InternAsset[])
    setLoading(false)
  }

  async function loadProjects(uid: string) {
    const sb = getSupabase()
    const { data } = await sb
      .from('intern_projects')
      .select('id, title')
      .eq('assigned_to', uid)
      .order('created_at', { ascending: false })
    setProjects((data || []) as InternProject[])
  }

  useEffect(() => {
    const sb = getSupabase()
    sb.auth.getUser().then(async ({ data: { user } }) => {
      if (!user) return
      setUserId(user.id)
      await Promise.all([loadAssets(user.id), loadProjects(user.id)])
    })
  }, [])

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSuccess(false)

    if (!form.title.trim()) { setError('Please enter a title'); return }
    if (!file) { setError('Please select a file to upload'); return }
    if (!userId) return

    setUploading(true)
    try {
      const sb = getSupabase()

      // Upload file to intern-assets bucket
      const ext = file.name.split('.').pop() || 'bin'
      const path = `${userId}/${Date.now()}-${file.name.replace(/[^a-zA-Z0-9._-]/g, '_')}`
      const { data: uploadData, error: uploadErr } = await sb.storage
        .from('intern-assets')
        .upload(path, file, { upsert: false })

      if (uploadErr) throw new Error(uploadErr.message)

      const { data: { publicUrl } } = sb.storage.from('intern-assets').getPublicUrl(path)

      // Insert row into intern_assets
      const { error: insertErr } = await sb.from('intern_assets').insert({
        title: form.title.trim(),
        asset_type: form.asset_type,
        project_id: form.project_id || null,
        file_url: publicUrl,
        notes: form.notes || null,
        status: 'pending',
        submitted_by: userId,
      })

      if (insertErr) throw new Error(insertErr.message)

      setSuccess(true)
      setForm({ title: '', asset_type: 'Social Media Graphic', project_id: '', notes: '' })
      setFile(null)
      if (fileRef.current) fileRef.current.value = ''
      await loadAssets(userId)
      setTimeout(() => setSuccess(false), 3000)
    } catch (err: any) {
      setError(err.message || 'Upload failed')
    } finally {
      setUploading(false)
    }
  }

  return (
    <LayoutShell>
      <div className="page-wrap" style={{ padding: '32px 48px', maxWidth: '900px', margin: '0 auto', width: '100%' }}>
        <div style={{ marginBottom: '28px' }}>
          <h1 style={{ fontSize: '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <Upload size={20} /> Assets
          </h1>
          <p style={{ fontSize: '13px', color: t.text.muted, marginTop: '2px' }}>Upload your work and track review status</p>
        </div>

        {/* Upload form */}
        <div style={{ ...card, marginBottom: '32px' }}>
          <h2 style={{ fontSize: '15px', fontWeight: '700', color: t.text.primary, marginBottom: '18px' }}>Submit New Asset</h2>
          <form onSubmit={handleSubmit}>
            <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: '14px', marginBottom: '14px' }}>
              <div>
                <label style={labelStyle}>Title *</label>
                <input
                  type="text"
                  value={form.title}
                  onChange={e => setForm(f => ({ ...f, title: e.target.value }))}
                  placeholder="e.g. July Instagram Post — NoCo"
                  style={inputStyle}
                />
              </div>
              <div>
                <label style={labelStyle}>Asset Type *</label>
                <select value={form.asset_type} onChange={e => setForm(f => ({ ...f, asset_type: e.target.value as AssetType }))} style={selectStyle}>
                  {ASSET_TYPES.map(at => <option key={at} value={at}>{at}</option>)}
                </select>
              </div>
              <div>
                <label style={labelStyle}>Project (optional)</label>
                <select value={form.project_id} onChange={e => setForm(f => ({ ...f, project_id: e.target.value }))} style={selectStyle}>
                  <option value="">No project</option>
                  {projects.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                </select>
              </div>
              <div>
                <label style={labelStyle}>File *</label>
                <input
                  ref={fileRef}
                  type="file"
                  accept="image/*,video/*,.pdf,.doc,.docx,.txt"
                  onChange={e => setFile(e.target.files?.[0] || null)}
                  style={{ ...inputStyle, padding: '8px 12px', cursor: 'pointer' }}
                />
              </div>
            </div>
            <div style={{ marginBottom: '14px' }}>
              <label style={labelStyle}>Notes (optional)</label>
              <textarea
                value={form.notes}
                onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
                placeholder="Context, references, or instructions for the reviewer..."
                rows={3}
                style={{ ...inputStyle, resize: 'vertical', minHeight: '72px' }}
              />
            </div>

            {error && (
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 14px', backgroundColor: t.status.dangerBg, borderRadius: '8px', color: t.status.danger, fontSize: '13px', marginBottom: '14px' }}>
                <AlertCircle size={14} />{error}
              </div>
            )}
            {success && (
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 14px', backgroundColor: t.status.successBg, borderRadius: '8px', color: t.status.success, fontSize: '13px', marginBottom: '14px' }}>
                <CheckCircle size={14} />Asset submitted for review!
              </div>
            )}

            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <button type="submit" disabled={uploading} style={{ ...btnPrimary, opacity: uploading ? 0.6 : 1 }}>
                <Upload size={14} />{uploading ? 'Uploading...' : 'Submit Asset'}
              </button>
            </div>
          </form>
        </div>

        {/* Submitted assets list */}
        <section>
          <h2 style={{ fontSize: '13px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '12px' }}>
            Submitted Assets ({assets.length})
          </h2>
          {loading ? (
            <div style={{ color: t.text.muted, fontSize: '14px' }}>Loading...</div>
          ) : assets.length === 0 ? (
            <div style={{ ...card, padding: '32px', textAlign: 'center', color: t.text.muted, fontSize: '14px' }}>
              No assets submitted yet. Use the form above to submit your first one.
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {assets.map(asset => {
                const s = STATUS_STYLE[asset.status] || STATUS_STYLE.pending
                return (
                  <div key={asset.id} style={{ ...card, padding: '16px 20px' }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: '12px' }}>
                      <div style={{ flex: 1 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '4px' }}>
                          <div style={{ fontSize: '14px', fontWeight: '600', color: t.text.primary }}>{asset.title}</div>
                          <span style={{ fontSize: '11px', fontWeight: '600', padding: '2px 8px', borderRadius: '12px', backgroundColor: s.bg, color: s.color }}>{s.label}</span>
                        </div>
                        <div style={{ fontSize: '12px', color: t.text.muted }}>
                          {asset.asset_type} · Submitted {formatShortDateMT(asset.created_at)}
                        </div>
                        {asset.notes && (
                          <div style={{ fontSize: '12px', color: t.text.secondary, marginTop: '4px' }}>{asset.notes}</div>
                        )}
                        {asset.status === 'changes_requested' && asset.feedback && (
                          <div style={{ marginTop: '10px', padding: '10px 14px', backgroundColor: t.status.dangerBg, borderRadius: '8px', borderLeft: `3px solid ${t.status.danger}` }}>
                            <div style={{ fontSize: '10px', fontWeight: '700', color: t.status.danger, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '4px' }}>Feedback</div>
                            <div style={{ fontSize: '13px', color: t.text.secondary }}>{asset.feedback}</div>
                          </div>
                        )}
                      </div>
                      {asset.file_url && (
                        <a href={asset.file_url} target="_blank" rel="noreferrer" style={{ fontSize: '12px', color: t.gold, textDecoration: 'none', flexShrink: 0, padding: '4px 10px', borderRadius: '6px', border: `1px solid ${t.goldBorder}` }}>
                          View File
                        </a>
                      )}
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </section>
      </div>
    </LayoutShell>
  )
}

'use client'
import { useState, useEffect } from 'react'
import { CheckSquare, ExternalLink, BookOpen, FolderOpen, Check } from 'lucide-react'
import LayoutShell from '../layout-shell'
import { getTasks } from '../lib/data'
import { getSupabase } from '../lib/supabase'
import { t, card } from '../lib/theme'
import { formatShortDateMT } from '../lib/formatters'

const RESOURCES = [
  { label: 'Brand Resources', href: '/intern/resources', icon: '📦' },
  { label: 'Campaigns', href: '/marketing', icon: '📣' },
]

export default function InternPage() {
  const [tasks, setTasks] = useState<any[]>([])
  const [doneThisWeek, setDoneThisWeek] = useState<number | null>(null)
  const [profile, setProfile] = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  useEffect(() => {
    const sb = getSupabase()
    sb.auth.getUser().then(async ({ data: { user } }) => {
      if (!user) return
      const { data: p } = await sb.from('user_profiles').select('*').eq('id', user.id).single()
      setProfile(p)
      try {
        const [openTasks, completedTasks] = await Promise.all([
          getTasks({ userId: user.id, completed: false }),
          getTasks({ userId: user.id, completed: true }),
        ])
        setTasks(openTasks)
        const weekAgo = new Date()
        weekAgo.setDate(weekAgo.getDate() - 7)
        setDoneThisWeek(completedTasks.filter((t: any) => t.completed_at && new Date(t.completed_at) >= weekAgo).length)
      } catch { /* RLS may block — show empty state */ }
      setLoading(false)
    }).catch(() => setLoading(false))
  }, [])

  async function complete(id: string) {
    const sb = getSupabase()
    await sb.from('tasks').update({ completed: true, completed_at: new Date().toISOString() }).eq('id', id)
    setTasks(prev => prev.filter(t => t.id !== id))
  }

  const openTasks = tasks.filter(t => !t.completed)
  const overdue = openTasks.filter(t => t.due_date && new Date(t.due_date) < new Date())

  return (
    <LayoutShell>
      <div style={{ padding: isMobile ? '16px' : '32px 48px', maxWidth: '1000px', margin: '0 auto', width: '100%' }}>
        <div style={{ marginBottom: '28px' }}>
          <h1 style={{ fontSize: '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em' }}>
            {profile?.name ? `Hey, ${profile.name.split(' ')[0]}` : 'Intern Dashboard'}
          </h1>
          <p style={{ fontSize: '13px', color: t.text.muted, marginTop: '2px' }}>Your work hub — tasks assigned to you, campaigns to support, and brand resources</p>
        </div>

        {/* Task summary */}
        <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : 'repeat(3, 1fr)', gap: '14px', marginBottom: '28px' }}>
          {[
            { label: 'Open Tasks', value: openTasks.length, color: openTasks.length > 0 ? t.gold : '#3dba78' },
            { label: 'Overdue', value: overdue.length, color: overdue.length > 0 ? '#e05252' : '#3dba78' },
            { label: 'Done This Week', value: doneThisWeek ?? '—', color: doneThisWeek != null && doneThisWeek > 0 ? '#3dba78' : t.text.muted },
          ].map(s => (
            <div key={s.label} style={{ ...card, padding: '16px 18px' }}>
              <div style={{ fontSize: '10px', color: t.text.muted, fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '6px' }}>{s.label}</div>
              <div style={{ fontSize: '24px', fontWeight: '700', color: s.color }}>{s.value}</div>
            </div>
          ))}
        </div>

        {/* Tasks */}
        <h2 style={{ fontSize: '15px', fontWeight: '700', color: t.text.primary, marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <CheckSquare size={16} /> Your Tasks
        </h2>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginBottom: '32px' }}>
          {openTasks.length === 0 ? (
            <div style={{ color: t.text.muted, fontSize: '14px', padding: '24px 0', textAlign: 'center' }}>All caught up! No open tasks.</div>
          ) : openTasks.map(task => {
            const isOverdue = task.due_date && new Date(task.due_date) < new Date()
            return (
              <div key={task.id} style={{ ...card, padding: '14px 18px', display: 'flex', alignItems: 'flex-start', gap: '12px', borderLeft: `3px solid ${isOverdue ? '#e05252' : t.border.default}` }}>
                <button onClick={() => complete(task.id)} style={{ marginTop: '2px', width: 22, height: 22, borderRadius: '6px', border: `1.5px solid ${t.border.hover}`, background: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                  <Check size={12} color={t.text.muted} />
                </button>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: '14px', fontWeight: '500', color: t.text.primary }}>{task.title}</div>
                  {task.description && <div style={{ fontSize: '12px', color: t.text.muted, marginTop: '2px' }}>{task.description}</div>}
                </div>
                {task.due_date && (
                  <div style={{ fontSize: '11px', color: isOverdue ? '#e05252' : t.text.muted, flexShrink: 0 }}>
                    {isOverdue ? 'Overdue · ' : ''}{formatShortDateMT(task.due_date)}
                  </div>
                )}
              </div>
            )
          })}
        </div>

        {/* Resources */}
        <h2 style={{ fontSize: '15px', fontWeight: '700', color: t.text.primary, marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <BookOpen size={16} /> Resources
        </h2>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '10px' }}>
          {RESOURCES.map(r => (
            <a key={r.label} href={r.href} style={{ ...card, padding: '14px 16px', textDecoration: 'none', display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
              <span style={{ fontSize: '18px' }}>{r.icon}</span>
              <span style={{ fontSize: '13px', fontWeight: '500', color: t.text.primary, flex: 1 }}>{r.label}</span>
              <ExternalLink size={12} color={t.text.muted} />
            </a>
          ))}
        </div>
      </div>
    </LayoutShell>
  )
}

'use client'
import { useState, useEffect } from 'react'
import { BookOpen, ExternalLink, Instagram, Globe, FileText } from 'lucide-react'
import LayoutShell from '../../layout-shell'
import { getClients } from '../../lib/data'
import { getSupabase } from '../../lib/supabase'
import { t, card } from '../../lib/theme'
import { clientLogoUrl } from '../../lib/constants'
import type { Client } from '../../lib/types'

interface BrandAsset {
  id: string
  client_slug: string
  title: string
  asset_type?: string
  url?: string
  description?: string
}

export default function InternResourcesPage() {
  const [clients, setClients] = useState<Client[]>([])
  const [assetMap, setAssetMap] = useState<Record<string, BrandAsset[]>>({})
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function load() {
      const sb = getSupabase()
      const cls = await getClients()
      setClients(cls)

      if (cls.length > 0) {
        const { data } = await sb
          .from('brand_assets')
          .select('*')
          .in('client_slug', cls.map(c => c.slug))
          .order('asset_type')
        const map: Record<string, BrandAsset[]> = {}
        for (const a of (data || [])) {
          if (!map[a.client_slug]) map[a.client_slug] = []
          map[a.client_slug].push(a)
        }
        setAssetMap(map)
      }

      setLoading(false)
    }
    load().catch(() => setLoading(false))
  }, [])

  if (loading) return <LayoutShell><div className="page-wrap" style={{ padding: '32px 48px', color: t.text.muted, fontSize: '14px' }}>Loading...</div></LayoutShell>

  return (
    <LayoutShell>
      <div className="page-wrap" style={{ padding: '32px 48px', maxWidth: '900px', margin: '0 auto', width: '100%' }}>
        <div style={{ marginBottom: '28px' }}>
          <h1 style={{ fontSize: '22px', fontWeight: '700', color: t.text.primary, letterSpacing: '-0.02em', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <BookOpen size={20} /> Brand Resources
          </h1>
          <p style={{ fontSize: '13px', color: t.text.muted, marginTop: '2px' }}>Everything you need to create content for each brand</p>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {clients.map(client => {
            const logo = clientLogoUrl(client)
            const assets = assetMap[client.slug] || []
            const linkAssets = assets.filter(a => a.url)
            const docAssets = assets.filter(a => !a.url)

            return (
              <div key={client.id} style={{ ...card, padding: '24px 28px', borderLeft: `3px solid ${client.color}` }}>

                {/* Brand header */}
                <div style={{ display: 'flex', alignItems: 'center', gap: '14px', marginBottom: '18px' }}>
                  {logo
                    ? <img src={logo} alt={client.name} style={{ width: 44, height: 44, objectFit: 'contain', borderRadius: '8px', backgroundColor: t.bg.elevated, padding: '4px' }} />
                    : <div style={{ width: 44, height: 44, borderRadius: '10px', backgroundColor: `${client.color}22`, border: `1px solid ${client.color}44`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                        <span style={{ fontSize: '20px', fontWeight: '700', color: client.color }}>{client.name[0]}</span>
                      </div>
                  }
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: '17px', fontWeight: '700', color: t.text.primary }}>{client.name}</div>
                    <div style={{ fontSize: '12px', color: t.text.muted }}>{client.category || 'Spirits Brand'}</div>
                  </div>

                  {/* Quick links */}
                  <div style={{ display: 'flex', gap: '10px' }}>
                    {client.instagram && (
                      <a href={`https://instagram.com/${client.instagram.replace('@', '')}`} target="_blank" rel="noreferrer"
                        style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '12px', color: t.text.muted, textDecoration: 'none', padding: '5px 10px', borderRadius: '6px', border: `1px solid ${t.border.default}` }}>
                        <Instagram size={13} /> {client.instagram.startsWith('@') ? client.instagram : `@${client.instagram}`}
                      </a>
                    )}
                    {client.website && (
                      <a href={client.website} target="_blank" rel="noreferrer"
                        style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '12px', color: t.text.muted, textDecoration: 'none', padding: '5px 10px', borderRadius: '6px', border: `1px solid ${t.border.default}` }}>
                        <Globe size={13} /> Website
                      </a>
                    )}
                  </div>
                </div>

                {/* Brand brief */}
                {client.notes && (
                  <div style={{ marginBottom: '18px', padding: '14px 16px', backgroundColor: t.bg.elevated, borderRadius: '8px', border: `1px solid ${t.border.subtle}` }}>
                    <div style={{ fontSize: '10px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '6px' }}>Brand Brief</div>
                    <p style={{ fontSize: '13px', color: t.text.secondary, lineHeight: 1.6, margin: 0 }}>{client.notes}</p>
                  </div>
                )}

                {/* Contact info */}
                {(client.contact_name || client.contact_email) && (
                  <div style={{ marginBottom: '18px' }}>
                    <div style={{ fontSize: '10px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '8px' }}>Brand Contact</div>
                    <div style={{ fontSize: '13px', color: t.text.secondary }}>
                      {client.contact_name}
                      {client.contact_email && <> · <a href={`mailto:${client.contact_email}`} style={{ color: t.status.info, textDecoration: 'none' }}>{client.contact_email}</a></>}
                      {client.contact_phone && <> · {client.contact_phone}</>}
                    </div>
                  </div>
                )}

                {/* Assets & links */}
                {linkAssets.length > 0 && (
                  <div style={{ marginBottom: docAssets.length > 0 ? '14px' : 0 }}>
                    <div style={{ fontSize: '10px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '8px' }}>Assets & Links</div>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '8px' }}>
                      {linkAssets.map(asset => (
                        <a key={asset.id} href={asset.url!} target="_blank" rel="noreferrer" style={{
                          display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 12px',
                          backgroundColor: t.bg.elevated, borderRadius: '8px', border: `1px solid ${t.border.default}`,
                          textDecoration: 'none', transition: 'border-color 150ms ease',
                        }}>
                          <ExternalLink size={13} color={client.color} style={{ flexShrink: 0 }} />
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div style={{ fontSize: '12px', fontWeight: '500', color: t.text.primary, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{asset.title}</div>
                            {asset.asset_type && <div style={{ fontSize: '10px', color: t.text.muted }}>{asset.asset_type}</div>}
                          </div>
                        </a>
                      ))}
                    </div>
                  </div>
                )}

                {/* Non-link assets */}
                {docAssets.length > 0 && (
                  <div>
                    <div style={{ fontSize: '10px', fontWeight: '700', color: t.text.muted, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '8px' }}>References</div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                      {docAssets.map(asset => (
                        <div key={asset.id} style={{ display: 'flex', alignItems: 'flex-start', gap: '8px', padding: '10px 12px', backgroundColor: t.bg.elevated, borderRadius: '8px', border: `1px solid ${t.border.default}` }}>
                          <FileText size={13} color={t.text.muted} style={{ flexShrink: 0, marginTop: '1px' }} />
                          <div>
                            <div style={{ fontSize: '12px', fontWeight: '500', color: t.text.primary }}>{asset.title}</div>
                            {asset.description && <div style={{ fontSize: '11px', color: t.text.muted, marginTop: '2px' }}>{asset.description}</div>}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {!client.notes && linkAssets.length === 0 && docAssets.length === 0 && (
                  <div style={{ fontSize: '13px', color: t.text.muted, fontStyle: 'italic' }}>No assets on file yet. Ask your manager to add brand guidelines and links.</div>
                )}
              </div>
            )
          })}
        </div>
      </div>
    </LayoutShell>
  )
}

