            <div>
              <div style={{ fontSize: '15px', fontWeight: '600', color: t.text.primary }}>{profile.name}</div>
              <div style={{ fontSize: '12px', color: t.text.muted, textTransform: 'capitalize' }}>{profile.role} · Barley Bros</div>
