        )}

        {/* ══ PLACEMENTS TAB ══ */}
        {activeTab === 'placements' && (
          <div>
            {activePlacements.length === 0 ? (
              <div style={{ fontSize: '13px', color: t.text.muted, padding: '60px 0', textAlign: 'center' }}>No active placements tracked yet.</div>
